import {
  Controller,
  Post,
  Body,
  Get,
  Query,
  Req,
  Res,
  HttpCode,
  HttpStatus,
  Logger,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Throttle, SkipThrottle } from '@nestjs/throttler';
import type { Request, Response } from 'express';
import { AuthService } from './auth.service';
import { RegisterDto, LoginDto } from './dto';
import { Public, CurrentUser, CurrentTenant } from '../../common/decorators';

// Cookie configuration
// Cookie configuration helpers
const getCookieOptions = (isProduction: boolean, domain?: string) => ({
  httpOnly: true,
  // Cross-site cookies (Frontend .com <-> Backend .dev) MUST be Secure and SameSite=None
  secure: true, // Required for SameSite=None. Relies on "trust proxy" in main.ts if running behind reverse proxy
  sameSite: 'none' as const,
  path: '/',
  domain: domain,
});

@Controller('auth')
export class AuthController {
  private readonly logger = new Logger(AuthController.name);

  constructor(
    private readonly authService: AuthService,
    private configService: ConfigService,
  ) {}

  private isProduction(): boolean {
    return this.configService.get('NODE_ENV') === 'production';
  }

  @Public()
  @Throttle({ auth: { limit: 10, ttl: 60000 } })
  @Post('register')
  async register(
    @Body() dto: RegisterDto,
    @Res({ passthrough: true }) res: Response,
    @Req() req: Request,
    @CurrentTenant() tenantId: string,
  ) {
    const result = await this.authService.register(dto, tenantId);

    // Establecer cookies (Primary method for same-domain/proxied)
    const hostname = req.get('host') || req.hostname;
    this.setAuthCookies(res, result.accessToken, result.refreshToken, hostname);

    // Retornar usuario Y tokens (Fallback for cross-domain where cookies are blocked)
    return {
      user: result.user,
      accessToken: result.accessToken,
      refreshToken: result.refreshToken,
      message: result.message,
    };
  }

  @Public()
  @Throttle({ auth: { limit: 10, ttl: 60000 } }) // 10 attempts per minute
  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(
    @Body() dto: LoginDto,
    @Res({ passthrough: true }) res: Response,
    @Req() req: Request,
    @CurrentTenant() tenantId: string,
  ) {
    const result = await this.authService.login(dto, tenantId);

    const hostname = req.get('host') || req.hostname;

    // Log solo en desarrollo
    if (!this.isProduction()) {
      this.logger.debug(`Login attempt from ${hostname}`);
    }

    // Establecer cookies
    this.setAuthCookies(res, result.accessToken, result.refreshToken, hostname);

    return {
      user: result.user,
      accessToken: result.accessToken,
      refreshToken: result.refreshToken,
    };
  }

  @Public()
  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  async refreshToken(
    @Req() req: Request,
    @Res({ passthrough: true }) res: Response,
    @Body() body: { refreshToken?: string }, // Allow passing token in body too
  ) {
    // Leer refresh token de la cookie O del body (fallback)
    const refreshToken = req.cookies?.refreshToken || body.refreshToken;

    if (!refreshToken) {
      res.status(401);
      return { message: 'No refresh token provided' };
    }

    const tokens = await this.authService.refreshToken(refreshToken);

    // Establecer nuevas cookies
    const hostname = req.get('host') || req.hostname;
    this.setAuthCookies(res, tokens.accessToken, tokens.refreshToken, hostname);

    return {
      message: 'Tokens refreshed successfully',
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
    };
  }

  @Public() // IMPORTANT: Logout must work even with expired/invalid tokens
  @SkipThrottle() // No limitar logout para evitar bloqueos
  @Post('logout')
  @HttpCode(HttpStatus.OK)
  async logout(@Req() req: Request, @Res({ passthrough: true }) res: Response) {
    const hostname = req.get('host') || req.hostname;

    // ALWAYS clear cookies, regardless of token validity
    this.clearAuthCookies(res, hostname);

    return { message: 'Sesión cerrada correctamente' };
  }

  @Public()
  @Post('forgot-password')
  @HttpCode(HttpStatus.OK)
  async forgotPassword(
    @Body('email') email: string,
    @CurrentTenant() tenantId: string,
  ) {
    return this.authService.forgotPassword(email, tenantId);
  }

  @Public()
  @Post('reset-password')
  @HttpCode(HttpStatus.OK)
  async resetPassword(@Body() dto: { token: string; password: string }) {
    return this.authService.resetPassword(dto.token, dto.password);
  }

  @Get('me')
  async getMe(@CurrentUser('id') userId: string) {
    return this.authService.getMe(userId);
  }

  // ============ Email Verification ============

  @Public()
  @Get('verify-email')
  async verifyEmail(@Query('token') token: string) {
    return this.authService.verifyEmail(token);
  }

  @Public()
  @Post('resend-verification')
  @HttpCode(HttpStatus.OK)
  async resendVerification(
    @Body('email') email: string,
    @CurrentTenant() tenantId: string,
  ) {
    return this.authService.resendVerificationEmail(email, tenantId);
  }

  // ============ Cookie Helpers ============

  private setAuthCookies(
    res: Response,
    accessToken: string,
    refreshToken: string,
    hostname?: string,
  ) {
    const isProd = this.isProduction();

    // Simplificado: No establecer dominio explícito.
    // Esto crea una cookie "Host Only" para el dominio de la API (ej: api.xn--...).
    // El navegador la enviará en peticiones fetch a la API siempre que credentials: 'include' esté activo.
    // Esto evita problemas con Punycode y subdominios.

    // Access token cookie (7 días)
    res.cookie('accessToken', accessToken, {
      ...getCookieOptions(isProd, undefined),
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 días
    });

    // Refresh token cookie (30 días)
    res.cookie('refreshToken', refreshToken, {
      ...getCookieOptions(isProd, undefined),
      maxAge: 30 * 24 * 60 * 60 * 1000, // 30 días
    });
  }

  private clearAuthCookies(res: Response, hostname?: string) {
    const isProd = this.isProduction();

    const clearOptions = {
      httpOnly: true,
      secure: isProd,
      sameSite: isProd ? ('none' as const) : ('lax' as const),
      path: '/',
    };

    // Clear without domain (Host Only match)
    res.clearCookie('accessToken', clearOptions);
    res.clearCookie('refreshToken', clearOptions);

    // Extra safely: set expired cookies with maxAge=0
    res.cookie('accessToken', '', { ...clearOptions, maxAge: 0 });
    res.cookie('refreshToken', '', { ...clearOptions, maxAge: 0 });
  }
}

import {
  Injectable,
  ConflictException,
  UnauthorizedException,
  BadRequestException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import * as bcrypt from 'bcryptjs';
import { randomBytes, createHash } from 'crypto';
import { PrismaService } from '../../prisma/prisma.service';
import { EmailService } from '../email/email.service';
import { RegisterDto, LoginDto } from './dto';
import { randomUUID } from 'crypto';

@Injectable()
export class AuthService {
  constructor(
    private prisma: PrismaService,
    private jwtService: JwtService,
    private configService: ConfigService,
    private emailService: EmailService,
  ) {}

  async register(dto: RegisterDto, tenantId: string) {
    // Resolver tenantId si viene como slug desde local (.env)
    let actualTenantId = tenantId;
    if (!tenantId.startsWith('c')) {
      const tenant = await this.prisma.secure.tenant.findUnique({
        where: { slug: tenantId },
        select: { id: true },
      });
      if (tenant) {
        actualTenantId = tenant.id;
      }
    }

    // Verificar si el email ya existe en este tenant
    const existingUser = await this.prisma.secure.user.findFirst({
      where: { tenantId: actualTenantId, email: dto.email.toLowerCase() },
    });

    if (existingUser) {
      throw new ConflictException('El email ya está registrado');
    }

    // Hashear contraseña
    const hashedPassword = await bcrypt.hash(dto.password, 12);

    // Crear usuario
    const user = await this.prisma.secure.user.create({
      data: {
        tenantId: actualTenantId,
        email: dto.email.toLowerCase(),
        password: hashedPassword,
        name: dto.name,
        emailVerified: false,
      },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        emailVerified: true,
        createdAt: true,
      },
    });

    // Generar y enviar email de verificación
    await this.sendVerificationEmail(user.id, user.email, user.name);

    // Generar tokens (el usuario puede loguearse pero no está verificado)
    const tokens = await this.generateTokens(
      user.id,
      user.email,
      user.role,
      user.name,
      tenantId,
    );

    return {
      user,
      ...tokens,
      message: 'Registro exitoso. Revisa tu email para verificar tu cuenta.',
    };
  }

  async login(dto: LoginDto, tenantId: string) {
    const MAX_FAILED_ATTEMPTS = 5;
    const LOCKOUT_DURATION_MINUTES = 15;

    // Resolver tenantId si viene como slug desde local (.env)
    let actualTenantId = tenantId;
    if (!tenantId.startsWith('c')) {
      const tenant = await this.prisma.secure.tenant.findUnique({
        where: { slug: tenantId },
        select: { id: true },
      });
      if (tenant) {
        actualTenantId = tenant.id;
      }
    }

    // Buscar usuario
    const user = await this.prisma.secure.user.findFirst({
      where: {
        tenantId: actualTenantId,
        email: dto.email.toLowerCase().trim(),
      },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        password: true,
        emailVerified: true,
        failedLoginAttempts: true,
        lockedUntil: true,
        subscription: {
          select: {
            status: true,
            endDate: true,
          },
        },
      },
    });

    if (!user) {
      throw new UnauthorizedException('Credenciales inválidas');
    }

    // Verificar si la cuenta está bloqueada
    if (user.lockedUntil && new Date() < user.lockedUntil) {
      const minutesLeft = Math.ceil(
        (user.lockedUntil.getTime() - Date.now()) / 60000,
      );
      throw new UnauthorizedException(
        `Cuenta bloqueada temporalmente.Intenta de nuevo en ${minutesLeft} minutos.`,
      );
    }

    // Si el bloqueo ya expiró, resetear el contador
    if (user.lockedUntil && new Date() >= user.lockedUntil) {
      await this.prisma.secure.user.update({
        where: { id: user.id },
        data: { failedLoginAttempts: 0, lockedUntil: null },
      });
    }

    // Verificar contraseña
    const isPasswordValid = await bcrypt.compare(dto.password, user.password);

    if (!isPasswordValid) {
      // Incrementar contador de intentos fallidos
      const newFailedAttempts = (user.failedLoginAttempts || 0) + 1;

      const updateData: { failedLoginAttempts: number; lockedUntil?: Date } = {
        failedLoginAttempts: newFailedAttempts,
      };

      // Si alcanzó el límite, bloquear cuenta
      if (newFailedAttempts >= MAX_FAILED_ATTEMPTS) {
        updateData.lockedUntil = new Date(
          Date.now() + LOCKOUT_DURATION_MINUTES * 60 * 1000,
        );
      }

      await this.prisma.secure.user.update({
        where: { id: user.id },
        data: updateData,
      });

      const attemptsLeft = MAX_FAILED_ATTEMPTS - newFailedAttempts;
      if (attemptsLeft > 0) {
        throw new UnauthorizedException(
          `Credenciales inválidas.${attemptsLeft} intento(s) restante(s).`,
        );
      } else {
        throw new UnauthorizedException(
          `Cuenta bloqueada por ${LOCKOUT_DURATION_MINUTES} minutos debido a múltiples intentos fallidos.`,
        );
      }
    }

    // Login exitoso: resetear contador de intentos fallidos
    if (user.failedLoginAttempts > 0 || user.lockedUntil) {
      await this.prisma.secure.user.update({
        where: { id: user.id },
        data: { failedLoginAttempts: 0, lockedUntil: null },
      });
    }

    // Generar tokens
    const tokens = await this.generateTokens(
      user.id,
      user.email,
      user.role,
      user.name,
      tenantId,
    );

    // Remover campos sensibles de la respuesta
    const {
      password: _,
      failedLoginAttempts: __,
      lockedUntil: ___,
      ...userWithoutSensitive
    } = user;

    return {
      user: {
        ...userWithoutSensitive,
        hasActiveSubscription:
          user.subscription?.status === 'ACTIVE' &&
          (!user.subscription?.endDate ||
            new Date(user.subscription.endDate) > new Date()),
      },
      ...tokens,
    };
  }

  async verifyEmail(token: string) {
    // Hash del token para buscar en DB
    const tokenHash = this.hashToken(token);

    // Buscar token
    const verificationToken =
      await this.prisma.secure.emailVerificationToken.findUnique({
        where: { token: tokenHash },
        include: { user: true },
      });

    if (!verificationToken) {
      throw new BadRequestException('Token de verificación inválido');
    }

    // Verificar expiración
    if (new Date() > verificationToken.expiresAt) {
      // Eliminar token expirado
      await this.prisma.secure.emailVerificationToken.delete({
        where: { id: verificationToken.id },
      });
      throw new BadRequestException(
        'El token ha expirado. Solicita uno nuevo.',
      );
    }

    // Marcar email como verificado
    await this.prisma.secure.user.update({
      where: { id: verificationToken.userId },
      data: { emailVerified: true },
    });

    // Eliminar token usado
    await this.prisma.secure.emailVerificationToken.delete({
      where: { id: verificationToken.id },
    });

    return {
      message: '¡Email verificado correctamente!',
      email: verificationToken.user.email,
    };
  }

  async resendVerificationEmail(email: string, tenantId: string) {
    // Resolver tenantId si viene como slug desde local (.env)
    let actualTenantId = tenantId;
    if (!tenantId.startsWith('c')) {
      const tenant = await this.prisma.secure.tenant.findUnique({
        where: { slug: tenantId },
        select: { id: true },
      });
      if (tenant) {
        actualTenantId = tenant.id;
      }
    }

    const user = await this.prisma.secure.user.findFirst({
      where: { tenantId: actualTenantId, email: email.toLowerCase() },
    });

    if (!user) {
      // No revelar si el email existe o no (seguridad)
      return {
        message:
          'Si el email está registrado, recibirás un correo de verificación.',
      };
    }

    if (user.emailVerified) {
      throw new BadRequestException('Este email ya está verificado');
    }

    // Rate limiting: máximo 3 tokens en la última hora
    const recentTokens = await this.prisma.secure.emailVerificationToken.count({
      where: {
        userId: user.id,
        createdAt: { gte: new Date(Date.now() - 3600000) }, // última hora
      },
    });

    if (recentTokens >= 3) {
      throw new BadRequestException(
        'Has solicitado demasiados emails. Intenta de nuevo en 1 hora.',
      );
    }

    // Eliminar tokens anteriores de este usuario
    await this.prisma.secure.emailVerificationToken.deleteMany({
      where: { userId: user.id },
    });

    // Enviar nuevo email
    await this.sendVerificationEmail(user.id, user.email, user.name);

    return {
      message:
        'Si el email está registrado, recibirás un correo de verificación.',
    };
  }

  private async sendVerificationEmail(
    userId: string,
    email: string,
    name: string,
  ) {
    // Generar token aleatorio (64 caracteres hex)
    const rawToken = randomBytes(32).toString('hex');

    // Guardar hash del token en la base de datos
    const tokenHash = this.hashToken(rawToken);
    const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 horas

    await this.prisma.secure.emailVerificationToken.create({
      data: {
        token: tokenHash,
        userId,
        expiresAt,
      },
    });

    // Enviar email con el token raw (no el hash)
    await this.emailService.sendVerificationEmail(email, name, rawToken);
  }

  private hashToken(token: string): string {
    return createHash('sha256').update(token).digest('hex');
  }

  async refreshToken(refreshToken: string) {
    // Buscar refresh token en la base de datos
    const storedToken = await this.prisma.secure.refreshToken.findUnique({
      where: { token: refreshToken },
      include: { user: true },
    });

    if (!storedToken) {
      throw new UnauthorizedException('Refresh token inválido');
    }

    // Verificar si ha expirado
    if (new Date() > storedToken.expiresAt) {
      // Eliminar token expirado
      await this.prisma.secure.refreshToken.deleteMany({
        where: { id: storedToken.id },
      });
      throw new UnauthorizedException('Refresh token expirado');
    }

    // Eliminar el token usado (rotación de tokens)
    await this.prisma.secure.refreshToken.deleteMany({
      where: { id: storedToken.id },
    });

    // Generar nuevos tokens (IMPORTANTE: pasar tenantId para que el JWT mantenga el contexto multi-tenant)
    const tokens = await this.generateTokens(
      storedToken.user.id,
      storedToken.user.email,
      storedToken.user.role,
      storedToken.user.name,
      storedToken.user.tenantId,
    );

    return tokens;
  }

  async logout(userId: string, refreshToken?: string) {
    if (refreshToken) {
      // Eliminar solo el token específico
      await this.prisma.secure.refreshToken.deleteMany({
        where: {
          userId,
          token: refreshToken,
        },
      });
    } else {
      // Eliminar todos los refresh tokens del usuario (logout de todos los dispositivos)
      await this.prisma.secure.refreshToken.deleteMany({
        where: { userId },
      });
    }

    return { message: 'Sesión cerrada correctamente' };
  }

  async getMe(userId: string) {
    const user = await this.prisma.secure.user.findUnique({
      where: { id: userId },
      select: {
        id: true,
        tenantId: true,
        email: true,
        name: true,
        role: true,
        avatar: true,
        emailVerified: true,
        createdAt: true,
        subscription: {
          select: {
            status: true,
            startDate: true,
            endDate: true,
          },
        },
      },
    });

    if (!user) {
      throw new UnauthorizedException('Usuario no encontrado');
    }

    return {
      ...user,
      hasActiveSubscription:
        user.subscription?.status === 'ACTIVE' &&
        (!user.subscription?.endDate ||
          new Date(user.subscription.endDate) > new Date()),
    };
  }

  private async generateTokens(
    userId: string,
    email: string,
    role?: string,
    name?: string,
    tenantId?: string,
  ) {
    const accessTokenPayload = { sub: userId, email, role, name, tenantId };

    // Generar tokens (Default 1 hora si no hay variable de entorno)
    const accessToken = await this.jwtService.signAsync(accessTokenPayload, {
      expiresIn: this.configService.get('JWT_ACCESS_EXPIRES_IN', '1h'),
    });

    // Crear refresh token
    const refreshTokenValue = randomUUID();
    const refreshTokenExpiresIn = this.configService.get(
      'JWT_REFRESH_EXPIRES_IN_DAYS',
      30,
    );
    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + refreshTokenExpiresIn);

    // Guardar refresh token en la base de datos
    await this.prisma.secure.refreshToken.create({
      data: {
        token: refreshTokenValue,
        userId,
        expiresAt,
      },
    });

    return {
      accessToken,
      refreshToken: refreshTokenValue,
      expiresIn: this.configService.get('JWT_ACCESS_EXPIRES_IN', '1h'),
    };
  }
  async forgotPassword(email: string, tenantId: string) {
    // Resolver tenantId si viene como slug desde local (.env)
    let actualTenantId = tenantId;
    if (!tenantId.startsWith('c')) {
      const tenant = await this.prisma.secure.tenant.findUnique({
        where: { slug: tenantId },
        select: { id: true },
      });
      if (tenant) {
        actualTenantId = tenant.id;
      }
    }

    const user = await this.prisma.secure.user.findFirst({
      where: { tenantId: actualTenantId, email: email.toLowerCase() },
    });

    if (!user) {
      // Security: Don't reveal if user exists
      return {
        message:
          'Si el email está registrado, recibirás instrucciones para restablecer tu contraseña.',
      };
    }

    // Generate token
    const rawToken = randomBytes(32).toString('hex');
    const tokenHash = this.hashToken(rawToken);
    const expiresAt = new Date(Date.now() + 3600000); // 1 hour

    // Save token (invalidate previous ones)
    await this.prisma.secure.passwordResetToken.deleteMany({
      where: { userId: user.id },
    });

    await this.prisma.secure.passwordResetToken.create({
      data: {
        token: tokenHash,
        userId: user.id,
        expiresAt,
      },
    });

    // Send email
    await this.emailService.sendPasswordRecoveryEmail(
      user.email,
      user.name,
      rawToken,
    );

    return {
      message:
        'Si el email está registrado, recibirás instrucciones para restablecer tu contraseña.',
    };
  }

  async resetPassword(token: string, newPassword: string) {
    const tokenHash = this.hashToken(token);

    const resetToken = await this.prisma.secure.passwordResetToken.findUnique({
      where: { token: tokenHash },
      include: { user: true },
    });

    if (!resetToken) {
      throw new BadRequestException('Token inválido o expirado.');
    }

    if (new Date() > resetToken.expiresAt) {
      await this.prisma.secure.passwordResetToken.delete({
        where: { id: resetToken.id },
      });
      throw new BadRequestException(
        'El token ha expirado. Solicita uno nuevo.',
      );
    }

    // Update password
    const hashedPassword = await bcrypt.hash(newPassword, 12);

    await this.prisma.secure.user.update({
      where: { id: resetToken.userId },
      data: {
        password: hashedPassword,
        // Unlock account if it was locked
        failedLoginAttempts: 0,
        lockedUntil: null,
      },
    });

    // Delete used token
    await this.prisma.secure.passwordResetToken.delete({
      where: { id: resetToken.id },
    });

    // Revoke all sessions (security best practice)
    await this.prisma.secure.refreshToken.deleteMany({
      where: { userId: resetToken.userId },
    });

    return {
      message:
        'Contraseña actualizada correctamente. Ya puedes iniciar sesión.',
    };
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Body,
  Param,
  Query,
  ParseIntPipe,
  DefaultValuePipe,
} from '@nestjs/common';
import { BlogService } from './blog.service';
import {
  CreatePostDto,
  UpdatePostDto,
  CreateCategoryDto,
  CreateTagDto,
  CreateAttachmentDto,
} from './dto';
import {
  Public,
  CurrentUser,
  Roles,
  CurrentTenant,
} from '../../common/decorators';

// ==================== PUBLIC BLOG CONTROLLER ====================
@Controller('blog')
export class BlogController {
  constructor(private readonly blogService: BlogService) {}

  @Get('posts')
  @Public()
  async getPublicPosts(
    @Query('page', new DefaultValuePipe(1), ParseIntPipe) page: number,
    @Query('limit', new DefaultValuePipe(10), ParseIntPipe) limit: number,
    @Query('category') category?: string,
  ) {
    return this.blogService.findPublicPosts(page, limit, category);
  }

  @Get('posts/:slug')
  @Public()
  async getPostBySlug(@Param('slug') slug: string, @CurrentUser() user?: any) {
    const hasSubscription =
      user?.hasActiveSubscription || user?.role === 'ADMIN' || false;
    return this.blogService.findPostBySlug(slug, hasSubscription);
  }

  @Get('categories')
  @Public()
  async getCategories() {
    return this.blogService.findAllCategories();
  }

  @Get('tags')
  @Public()
  async getTags() {
    return this.blogService.findAllTags();
  }
}

// ==================== ADMIN BLOG CONTROLLER ====================
@Controller('admin/blog')
@Roles('ADMIN')
export class AdminBlogController {
  constructor(private readonly blogService: BlogService) {}

  // Posts
  @Get('posts')
  async getAllPosts(
    @Query('page', new DefaultValuePipe(1), ParseIntPipe) page: number,
    @Query('limit', new DefaultValuePipe(10), ParseIntPipe) limit: number,
    @Query('published') published?: string,
  ) {
    const publishedFilter =
      published === 'true' ? true : published === 'false' ? false : undefined;
    return this.blogService.findAllPosts(page, limit, publishedFilter);
  }

  @Get('posts/:id')
  async getPost(@Param('id') id: string) {
    return this.blogService.findPostById(id);
  }

  @Post('posts')
  async createPost(
    @Body() dto: CreatePostDto,
    @CurrentTenant() tenantId: string,
  ) {
    return this.blogService.createPost(dto, tenantId);
  }

  @Patch('posts/:id')
  async updatePost(@Param('id') id: string, @Body() dto: UpdatePostDto) {
    return this.blogService.updatePost(id, dto);
  }

  @Delete('posts/:id')
  async deletePost(@Param('id') id: string) {
    return this.blogService.deletePost(id);
  }

  // Attachments
  @Get('posts/:postId/attachments')
  async getAttachments(@Param('postId') postId: string) {
    return this.blogService.findAttachmentsByPostId(postId);
  }

  @Post('posts/:postId/attachments')
  async addAttachment(
    @Param('postId') postId: string,
    @Body() dto: CreateAttachmentDto,
  ) {
    return this.blogService.addAttachment(postId, dto);
  }

  @Delete('attachments/:id')
  async removeAttachment(@Param('id') id: string) {
    return this.blogService.removeAttachment(id);
  }

  // Categories
  @Post('categories')
  async createCategory(
    @Body() dto: CreateCategoryDto,
    @CurrentTenant() tenantId: string,
  ) {
    return this.blogService.createCategory(dto, tenantId);
  }

  @Delete('categories/:id')
  async deleteCategory(@Param('id') id: string) {
    return this.blogService.deleteCategory(id);
  }

  // Tags
  @Post('tags')
  async createTag(
    @Body() dto: CreateTagDto,
    @CurrentTenant() tenantId: string,
  ) {
    return this.blogService.createTag(dto, tenantId);
  }

  @Delete('tags/:id')
  async deleteTag(@Param('id') id: string) {
    return this.blogService.deleteTag(id);
  }
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import {
  CreatePostDto,
  UpdatePostDto,
  CreateCategoryDto,
  CreateTagDto,
  CreateAttachmentDto,
} from './dto';

@Injectable()
export class BlogService {
  constructor(private prisma: PrismaService) {}

  // ==================== POSTS ====================

  async createPost(dto: CreatePostDto, tenantId: string) {
    const slug = this.generateSlug(dto.title);
    const readingTime =
      dto.readingTime || this.calculateReadingTime(dto.content);

    // Crear el post primero
    const post = await this.prisma.secure.post.create({
      data: {
        tenantId,
        title: dto.title,
        slug,
        excerpt: dto.excerpt,
        content: dto.content,
        coverImage: dto.coverImage,
        published: dto.published,
        isPremium: dto.isPremium,
        authorName: 'Mauricio Mera',
        publishedAt: dto.published ? new Date() : null,
        metaTitle: dto.metaTitle,
        metaDescription: dto.metaDescription,
        readingTime,
      },
    });

    // Conectar categoría si existe
    if (dto.categoryId) {
      await this.prisma.categoriesOnPosts.create({
        data: {
          postId: post.id,
          categoryId: dto.categoryId,
        },
      });
    }

    // Conectar tags si existen
    if (dto.tagIds?.length) {
      await this.prisma.tagsOnPosts.createMany({
        data: dto.tagIds.map((tagId) => ({
          postId: post.id,
          tagId,
        })),
      });
    }

    return this.findPostById(post.id);
  }

  async updatePost(id: string, dto: UpdatePostDto) {
    const existingPost = await this.prisma.secure.post.findUnique({
      where: { id },
    });
    if (!existingPost) {
      throw new NotFoundException('Post no encontrado');
    }

    // Preparar datos de actualización
    const updateData: any = {};
    if (dto.title !== undefined) {
      updateData.title = dto.title;
      updateData.slug = this.generateSlug(dto.title);
    }
    if (dto.excerpt !== undefined) updateData.excerpt = dto.excerpt;
    if (dto.content !== undefined) {
      updateData.content = dto.content;
      updateData.readingTime = this.calculateReadingTime(dto.content);
    }
    if (dto.coverImage !== undefined) updateData.coverImage = dto.coverImage;
    if (dto.published !== undefined) {
      updateData.published = dto.published;
      if (dto.published && !existingPost.publishedAt) {
        updateData.publishedAt = new Date();
      }
    }
    if (dto.isPremium !== undefined) updateData.isPremium = dto.isPremium;
    if (dto.metaTitle !== undefined) updateData.metaTitle = dto.metaTitle;
    if (dto.metaDescription !== undefined)
      updateData.metaDescription = dto.metaDescription;

    // Actualizar el post
    await this.prisma.secure.post.update({
      where: { id },
      data: updateData,
    });

    // Actualizar categoría si se proporciona
    if (dto.categoryId !== undefined) {
      await this.prisma.categoriesOnPosts.deleteMany({
        where: { postId: id },
      });
      if (dto.categoryId) {
        await this.prisma.categoriesOnPosts.create({
          data: { postId: id, categoryId: dto.categoryId },
        });
      }
    }

    // Actualizar tags si se proporcionan
    if (dto.tagIds !== undefined) {
      await this.prisma.tagsOnPosts.deleteMany({
        where: { postId: id },
      });
      if (dto.tagIds.length) {
        await this.prisma.tagsOnPosts.createMany({
          data: dto.tagIds.map((tagId) => ({ postId: id, tagId })),
        });
      }
    }

    return this.findPostById(id);
  }

  async deletePost(id: string) {
    const post = await this.prisma.secure.post.findUnique({ where: { id } });
    if (!post) {
      throw new NotFoundException('Post no encontrado');
    }

    await this.prisma.secure.post.delete({ where: { id } });
    return { message: 'Post eliminado correctamente' };
  }

  async findAllPosts(page = 1, limit = 10, published?: boolean) {
    const skip = (page - 1) * limit;

    const where: any = {};
    if (published !== undefined) {
      where.published = published;
    }

    const [posts, total] = await Promise.all([
      this.prisma.secure.post.findMany({
        where,
        skip,
        take: limit,
        orderBy: { createdAt: 'desc' },
        include: {
          categories: { include: { category: true } },
          tags: { include: { tag: true } },
          attachments: true,
        },
      }),
      this.prisma.secure.post.count({ where }),
    ]);

    const transformedPosts = posts.map((post) => ({
      ...post,
      categories: post.categories.map((c) => c.category),
      tags: post.tags.map((t) => t.tag),
    }));

    return {
      data: transformedPosts,
      meta: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  async findPublicPosts(page = 1, limit = 10, categorySlug?: string) {
    const skip = (page - 1) * limit;

    const where: any = { published: true };
    if (categorySlug) {
      where.categories = {
        some: {
          category: { slug: categorySlug },
        },
      };
    }

    const [posts, total] = await Promise.all([
      this.prisma.secure.post.findMany({
        where,
        skip,
        take: limit,
        orderBy: { createdAt: 'desc' },
        select: {
          id: true,
          title: true,
          slug: true,
          excerpt: true,
          coverImage: true,
          isPremium: true,
          authorName: true,
          createdAt: true,
          readingTime: true,
          categories: { include: { category: true } },
          tags: { include: { tag: true } },
        },
      }),
      this.prisma.secure.post.count({ where }),
    ]);

    const transformedPosts = posts.map((post) => ({
      ...post,
      categories: post.categories.map((c) => c.category),
      tags: post.tags.map((t) => t.tag),
    }));

    return {
      data: transformedPosts,
      meta: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit),
      },
    };
  }

  async findPostBySlug(
    slug: string,
    hasSubscription = false,
    tenantId?: string,
  ) {
    const post = await this.prisma.secure.post.findFirst({
      where: { slug, ...(tenantId ? { tenantId } : {}) },
      include: {
        categories: { include: { category: true } },
        tags: { include: { tag: true } },
        attachments: true,
      },
    });

    if (!post) {
      throw new NotFoundException('Post no encontrado');
    }

    if (!post.published) {
      throw new NotFoundException('Post no encontrado');
    }

    const transformedPost = {
      ...post,
      categories: post.categories.map((c) => c.category),
      tags: post.tags.map((t) => t.tag),
    };

    // Si es premium y el usuario no tiene suscripción, limitar contenido
    if (post.isPremium && !hasSubscription) {
      return {
        ...transformedPost,
        content: post.content.substring(0, 500) + '...',
        isContentLimited: true,
        attachments: [], // No mostrar adjuntos premium
      };
    }

    return { ...transformedPost, isContentLimited: false };
  }

  async findPostById(id: string) {
    const post = await this.prisma.secure.post.findUnique({
      where: { id },
      include: {
        categories: { include: { category: true } },
        tags: { include: { tag: true } },
        attachments: true,
      },
    });

    if (!post) {
      throw new NotFoundException('Post no encontrado');
    }

    return {
      ...post,
      categories: post.categories.map((c) => c.category),
      tags: post.tags.map((t) => t.tag),
    };
  }

  // ==================== ATTACHMENTS ====================

  async addAttachment(postId: string, dto: CreateAttachmentDto) {
    const post = await this.prisma.secure.post.findUnique({
      where: { id: postId },
    });
    if (!post) {
      throw new NotFoundException('Post no encontrado');
    }

    return this.prisma.postAttachment.create({
      data: {
        postId,
        name: dto.name,
        fileUrl: dto.fileUrl,
        fileType: dto.fileType,
        fileSize: dto.fileSize,
        isPublic: dto.isPublic ?? !post.isPremium,
      },
    });
  }

  async removeAttachment(attachmentId: string) {
    const attachment = await this.prisma.postAttachment.findUnique({
      where: { id: attachmentId },
    });

    if (!attachment) {
      throw new NotFoundException('Adjunto no encontrado');
    }

    await this.prisma.postAttachment.delete({
      where: { id: attachmentId },
    });
    return {
      message: 'Adjunto eliminado correctamente',
      fileUrl: attachment.fileUrl,
    };
  }

  async findAttachmentsByPostId(postId: string) {
    return this.prisma.postAttachment.findMany({
      where: { postId },
      orderBy: { createdAt: 'asc' },
    });
  }

  // ==================== CATEGORIES ====================

  async createCategory(dto: CreateCategoryDto, tenantId: string) {
    const slug = this.generateSlug(dto.name);

    return this.prisma.secure.category.create({
      data: {
        tenantId,
        name: dto.name,
        slug,
        type: 'BLOG',
      },
    });
  }

  async findAllCategories() {
    return this.prisma.secure.category.findMany({
      where: { type: 'BLOG' },
      orderBy: { name: 'asc' },
      include: {
        _count: { select: { posts: true } },
      },
    });
  }

  async deleteCategory(id: string) {
    const category = await this.prisma.secure.category.findFirst({
      where: { id, type: 'BLOG' },
    });
    if (!category) {
      throw new NotFoundException('Categoría no encontrada');
    }

    await this.prisma.secure.category.delete({ where: { id } });
    return { message: 'Categoría eliminada correctamente' };
  }

  // ==================== TAGS ====================

  async createTag(dto: CreateTagDto, tenantId: string) {
    return this.prisma.secure.tag.create({
      data: {
        tenantId,
        name: dto.name,
      },
    });
  }

  async findAllTags() {
    return this.prisma.secure.tag.findMany({
      orderBy: { name: 'asc' },
      include: {
        _count: { select: { posts: true } },
      },
    });
  }

  async deleteTag(id: string) {
    const tag = await this.prisma.secure.tag.findUnique({ where: { id } });
    if (!tag) {
      throw new NotFoundException('Tag no encontrado');
    }

    await this.prisma.secure.tag.delete({ where: { id } });
    return { message: 'Tag eliminado correctamente' };
  }

  // ==================== HELPERS ====================

  private generateSlug(title: string): string {
    return (
      title
        .toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/[^a-z0-9\s-]/g, '')
        .replace(/\s+/g, '-')
        .replace(/-+/g, '-')
        .replace(/^-|-$/g, '') +
      '-' +
      Date.now().toString(36)
    );
  }

  private calculateReadingTime(content: string): number {
    // Promedio de palabras por minuto de lectura
    const wordsPerMinute = 200;

    // Eliminar HTML tags y contar palabras
    const text = content.replace(/<[^>]*>/g, '');
    const wordCount = text
      .split(/\s+/)
      .filter((word) => word.length > 0).length;

    // Calcular minutos (mínimo 1 minuto)
    return Math.max(1, Math.ceil(wordCount / wordsPerMinute));
  }
}

import {
  Injectable,
  Logger,
  NotFoundException,
  BadRequestException,
  Inject,
} from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import type { Cache } from 'cache-manager';
import { PrismaService } from '../../prisma/prisma.service';
import { CreateCategoryDto } from './dto/create-category.dto';
import { UpdateCategoryDto } from './dto/update-category.dto';
import { CategoryType } from '@alvarosky/database';

function slugify(text: string) {
  return text
    .toString()
    .toLowerCase()
    .replace(/\s+/g, '-') // Replace spaces with -
    .replace(/[^\w\-]+/g, '') // Remove all non-word chars
    .replace(/\-\-+/g, '-') // Replace multiple - with single -
    .replace(/^-+/, '') // Trim - from start of text
    .replace(/-+$/, ''); // Trim - from end of text
}

@Injectable()
export class CategoriesService {
  private readonly logger = new Logger(CategoriesService.name);

  constructor(
    private readonly prisma: PrismaService,
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
  ) {}

  private async invalidateMenuCache(tenantId: string) {
    const keys = [
      `tenant:${tenantId}:menu_context`,
      `tenant:${tenantId}:product_catalog`,
    ];
    await Promise.all(keys.map((k) => this.cacheManager.del(k)));
    this.logger.log(
      `[Tenant: ${tenantId}] Caché de menú y catálogo de WhatsApp invalidado.`,
    );
  }

  async findAll(tenantId: string, type: CategoryType = 'PRODUCT') {
    return this.prisma.secure.category.findMany({
      where: { tenantId, type },
      orderBy: { name: 'asc' },
    });
  }

  async findOne(tenantId: string, id: string) {
    const category = await this.prisma.secure.category.findUnique({
      where: { id },
    });

    // Verificación IDOR doble, aunque no haga falta si el endpoint inyecta el param
    if (!category || category.tenantId !== tenantId) {
      throw new NotFoundException(`Categoria con ID ${id} no encontrada`);
    }
    return category;
  }

  async create(
    tenantId: string,
    createDto: CreateCategoryDto,
    type: CategoryType = 'PRODUCT',
  ) {
    const slug = slugify(createDto.name);
    const ORConditions: any[] = [{ name: createDto.name }];

    if (slug) {
      ORConditions.push({ slug });
    }

    // Verificar unicidad de nombre / slug por tenant Y tipo
    const existing = await this.prisma.secure.category.findFirst({
      where: {
        tenantId,
        type,
        OR: ORConditions,
      },
    });

    console.log('[DEBUG_CATEGORY] Payload:', {
      name: createDto.name,
      slug,
      tenantId,
      type,
    });
    console.log('[DEBUG_CATEGORY] Match found:', existing);

    if (existing) {
      throw new BadRequestException(
        `Ya existe una categoría de tipo ${type} con este nombre.`,
      );
    }

    const category = await this.prisma.secure.category.create({
      data: {
        tenantId,
        name: createDto.name,
        slug,
        type,
      },
    });

    await this.invalidateMenuCache(tenantId);
    return category;
  }

  async update(
    tenantId: string,
    id: string,
    updateDto: UpdateCategoryDto,
    type: CategoryType = 'PRODUCT',
  ) {
    // Verificar que exista y pertenezca al tenant (Prevencion IDOR)
    const existing = await this.prisma.secure.category.findFirst({
      where: { id, tenantId, type },
    });

    if (!existing) {
      throw new NotFoundException(
        `Categoria con ID ${id} no encontrada en este Tenant`,
      );
    }

    let slug = existing.slug;
    if (updateDto.name && updateDto.name !== existing.name) {
      slug = slugify(updateDto.name);

      const slugConflict = await this.prisma.secure.category.findFirst({
        where: { tenantId, slug, type, NOT: { id } },
      });
      if (slugConflict)
        throw new BadRequestException('El nombre genera un slug ya en uso.');
    }

    const category = await this.prisma.secure.category.update({
      where: { id }, // Ya confirmamos que le pertenece al tenantId arriba. Opcional podria ser un UpdateMany pero Update arroja el error de Unique más rapido y devuelve registro
      data: {
        name: updateDto.name,
        slug,
      },
    });

    await this.invalidateMenuCache(tenantId);
    return category;
  }

  async remove(tenantId: string, id: string, type: CategoryType = 'PRODUCT') {
    // Prevenir IDOR
    const existing = await this.prisma.secure.category.findFirst({
      where: { id, tenantId, type },
    });

    if (!existing) {
      throw new NotFoundException(
        `Categoria con ID ${id} no encontrada en este Tenant`,
      );
    }

    // Comprobar Productos Asociados en la tabla Pivot CategoriesOnProducts
    const productCount = await this.prisma.categoriesOnProducts.count({
      where: { categoryId: id },
    });

    if (productCount > 0) {
      throw new BadRequestException(
        `No se puede eliminar la categoría porque tiene ${productCount} productos asociados.`,
      );
    }

    // Permitido borrar
    await this.prisma.secure.category.delete({
      where: { id },
    });

    await this.invalidateMenuCache(tenantId);

    this.logger.log(`Categoria eliminada ID: ${id} x Tenant ID: ${tenantId}`);
    return { success: true };
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '../../prisma/prisma.service';

@Injectable()
export class CorsCacheService implements OnModuleInit {
  private readonly logger = new Logger(CorsCacheService.name);
  private readonly allowedOrigins = new Set<string>();
  private readonly baseDomain: string;

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
  ) {
    this.baseDomain =
      this.configService.get<string>('NEXT_PUBLIC_BASE_DOMAIN') ||
      'xn--alvarolondoo-khb.dev';
  }

  async onModuleInit() {
    await this.loadOriginsFromDb();
  }

  /**
   * Carga todos los dominios existentes de tenants en la caché RAM.
   * Se ejecuta una sola vez al iniciar el módulo.
   */
  private async loadOriginsFromDb(): Promise<void> {
    try {
      const tenants = await this.prisma.tenant.findMany({
        select: { slug: true, domain: true },
      });

      for (const tenant of tenants) {
        // Subdomain origin: https://{slug}.{baseDomain}
        if (tenant.slug) {
          this.allowedOrigins.add(`https://${tenant.slug}.${this.baseDomain}`);
        }

        // Custom domain origin: https://{domain}
        if (tenant.domain) {
          this.allowedOrigins.add(`https://${tenant.domain}`);
        }
      }

      this.logger.log(
        `CORS Cache inicializado con ${this.allowedOrigins.size} orígenes de ${tenants.length} tenants`,
      );
    } catch (error: any) {
      this.logger.error(
        `Error cargando orígenes CORS desde la DB: ${error.message}`,
      );
    }
  }

  /**
   * Agrega un nuevo origen al caché en RAM (sin reiniciar el servidor).
   * Se llama después de crear un nuevo Tenant.
   */
  addOrigin(origin: string): void {
    this.allowedOrigins.add(origin);
    this.logger.log(`Nuevo origen CORS agregado al caché: ${origin}`);
  }

  /**
   * Verifica si un origen está permitido en la caché RAM.
   */
  checkOrigin(origin: string): boolean {
    return this.allowedOrigins.has(origin);
  }

  /**
   * Devuelve el dominio base configurado.
   */
  getBaseDomain(): string {
    return this.baseDomain;
  }
}

import {
  Injectable,
  Logger,
  NotFoundException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import { MovementType, AdjustmentType, CountStatus } from '@alvarosky/database';
import {
  CreateInventoryCountDto,
  CompleteInventoryCountDto,
} from './dto/inventory-count.dto';

@Injectable()
export class InventoryCountsService {
  private readonly logger = new Logger(InventoryCountsService.name);

  constructor(private prisma: PrismaService) {}

  async create(tenantId: string, userId: string, dto: CreateInventoryCountDto) {
    // Verify warehouse
    const warehouse = await this.prisma.secure.warehouse.findFirst({
      where: { id: dto.warehouseId, tenantId },
    });
    if (!warehouse) throw new NotFoundException('Almacén no encontrado');

    // Get all active inventory items and their current stock in this warehouse
    const items = await this.prisma.secure.inventoryItem.findMany({
      where: { tenantId, isActive: true },
      include: {
        stock: {
          where: { warehouseId: dto.warehouseId },
        },
      },
      orderBy: { name: 'asc' },
    });

    // Create count with pre-populated lines (system stock snapshot)
    return this.prisma.secure.inventoryCount.create({
      data: {
        tenantId,
        warehouseId: dto.warehouseId,
        countedBy: userId,
        notes: dto.notes,
        status: CountStatus.DRAFT,
        lines: {
          create: items.map((item) => ({
            inventoryItemId: item.id,
            systemStock: item.stock[0]?.currentStock ?? 0,
          })),
        },
      },
      include: {
        warehouse: { select: { id: true, name: true } },
        lines: {
          include: {
            inventoryItem: { select: { id: true, name: true, unit: true } },
          },
          orderBy: { inventoryItem: { name: 'asc' } },
        },
      },
    });
  }

  async findAll(tenantId: string) {
    return this.prisma.secure.inventoryCount.findMany({
      where: { tenantId },
      include: {
        warehouse: { select: { id: true, name: true } },
        _count: { select: { lines: true } },
      },
      orderBy: { createdAt: 'desc' },
    });
  }

  async findOne(id: string, tenantId: string) {
    const count = await this.prisma.secure.inventoryCount.findFirst({
      where: { id, tenantId },
      include: {
        warehouse: { select: { id: true, name: true } },
        lines: {
          include: {
            inventoryItem: { select: { id: true, name: true, unit: true } },
          },
          orderBy: { inventoryItem: { name: 'asc' } },
        },
      },
    });
    if (!count) throw new NotFoundException('Conteo no encontrado');
    return count;
  }

  async complete(
    id: string,
    tenantId: string,
    userId: string,
    dto: CompleteInventoryCountDto,
  ) {
    const count = await this.prisma.secure.inventoryCount.findFirst({
      where: { id, tenantId, status: CountStatus.DRAFT },
      include: { lines: true },
    });
    if (!count) {
      throw new NotFoundException('Conteo no encontrado o ya fue completado');
    }

    return this.prisma.$transaction(async (tx) => {
      // Paso 1: Preparar datos y calcular diferencias
      const updates: {
        lineId: string;
        inventoryItemId: string;
        countedStock: number;
        diff: number;
        adjustmentType?: AdjustmentType;
      }[] = [];

      for (const lineDto of dto.lines) {
        const existingLine = count.lines.find(
          (l) => l.inventoryItemId === lineDto.inventoryItemId,
        );
        if (!existingLine) continue;

        const diff = lineDto.countedStock - Number(existingLine.systemStock);
        updates.push({
          lineId: existingLine.id,
          inventoryItemId: lineDto.inventoryItemId,
          countedStock: lineDto.countedStock,
          diff,
          adjustmentType: lineDto.adjustmentType,
        });
      }

      // Paso 2: Batch update de countLines (paralelo)
      await Promise.all(
        updates.map((u) =>
          tx.inventoryCountLine.update({
            where: { id: u.lineId },
            data: {
              countedStock: u.countedStock,
              difference: u.diff,
              adjustmentType:
                u.diff !== 0 ? u.adjustmentType || AdjustmentType.MERMA : null,
            },
          }),
        ),
      );

      // Paso 3: Batch createMany para movements (1 query)
      const withDiff = updates.filter((u) => u.diff !== 0);
      if (withDiff.length > 0) {
        await tx.inventoryMovement.createMany({
          data: withDiff.map((u) => ({
            tenantId,
            inventoryItemId: u.inventoryItemId,
            warehouseId: count.warehouseId,
            type: MovementType.ADJUSTMENT,
            quantity: u.diff,
            reason: `Ajuste por conteo físico (${u.diff > 0 ? 'sobrante' : u.adjustmentType === 'FUGA' ? 'fuga' : 'merma'})`,
            reference: id,
            createdBy: userId,
          })),
        });

        // Paso 4: Batch upserts de stock (paralelo)
        await Promise.all(
          withDiff.map((u) =>
            tx.warehouseStock.upsert({
              where: {
                warehouseId_inventoryItemId: {
                  warehouseId: count.warehouseId,
                  inventoryItemId: u.inventoryItemId,
                },
              },
              create: {
                warehouseId: count.warehouseId,
                inventoryItemId: u.inventoryItemId,
                currentStock: u.countedStock,
              },
              update: {
                currentStock: u.countedStock,
              },
            }),
          ),
        );
      }

      // Mark count as completed
      const completed = await tx.inventoryCount.update({
        where: { id },
        data: {
          status: CountStatus.COMPLETED,
          completedAt: new Date(),
        },
        include: {
          warehouse: { select: { id: true, name: true } },
          lines: {
            include: {
              inventoryItem: { select: { id: true, name: true, unit: true } },
            },
          },
        },
      });

      this.logger.log(`Conteo ${id} completado con ${dto.lines.length} líneas`);

      return completed;
    });
  }

  async delete(id: string, tenantId: string) {
    const count = await this.prisma.secure.inventoryCount.findFirst({
      where: { id, tenantId, status: CountStatus.DRAFT },
    });
    if (!count) {
      throw new NotFoundException('Conteo no encontrado o ya fue completado');
    }

    return this.prisma.secure.inventoryCount.delete({ where: { id } });
  }
}

import {
  Injectable,
  NotFoundException,
  BadRequestException,
} from '@nestjs/common';
import { PrismaService } from '../../prisma/prisma.service';
import {
  CreateEvaluationDto,
  UpdateEvaluationDto,
  SubmitEvaluationDto,
  CreateQuestionDto,
} from './dto';

@Injectable()
export class EvaluationService {
  constructor(private prisma: PrismaService) {}

  // ==================== EVALUATIONS ====================

  async createEvaluation(dto: CreateEvaluationDto) {
    // Verificar que el tema existe y no tiene evaluación
    const theme = await this.prisma.secure.theme.findUnique({
      where: { id: dto.themeId },
      include: { evaluation: true },
    });

    if (!theme) throw new NotFoundException('Tema no encontrado');
    if (theme.evaluation)
      throw new BadRequestException('Este tema ya tiene una evaluación');

    const { questions, ...evaluationData } = dto;

    return this.prisma.evaluation.create({
      data: {
        ...evaluationData,
        questions: questions?.length
          ? {
              create: questions.map((q, index) => ({
                question: q.question,
                image: q.image,
                options: q.options as any,
                correctId: q.correctId,
                order: q.order ?? index,
              })),
            }
          : undefined,
      },
      include: {
        questions: { orderBy: { order: 'asc' } },
        theme: { select: { id: true, title: true } },
      },
    });
  }

  async updateEvaluation(id: string, dto: UpdateEvaluationDto) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id },
    });
    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');

    return this.prisma.evaluation.update({
      where: { id },
      data: dto,
      include: {
        questions: { orderBy: { order: 'asc' } },
        theme: { select: { id: true, title: true } },
      },
    });
  }

  async deleteEvaluation(id: string) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id },
    });
    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');

    await this.prisma.evaluation.delete({ where: { id } });
    return { message: 'Evaluación eliminada correctamente' };
  }

  async findEvaluationById(id: string) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id },
      include: {
        questions: { orderBy: { order: 'asc' } },
        theme: { select: { id: true, title: true } },
        _count: { select: { results: true } },
      },
    });
    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');
    return evaluation;
  }

  // ==================== QUESTIONS ====================

  async addQuestion(evaluationId: string, dto: CreateQuestionDto) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id: evaluationId },
    });
    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');

    // Obtener el orden máximo actual
    const maxOrder = await this.prisma.question.aggregate({
      where: { evaluationId },
      _max: { order: true },
    });

    return this.prisma.question.create({
      data: {
        evaluationId,
        question: dto.question,
        image: dto.image,
        options: dto.options as any,
        correctId: dto.correctId,
        order: dto.order ?? (maxOrder._max.order ?? 0) + 1,
      },
    });
  }

  async updateQuestion(id: string, dto: Partial<CreateQuestionDto>) {
    const question = await this.prisma.question.findUnique({
      where: { id },
    });
    if (!question) throw new NotFoundException('Pregunta no encontrada');

    return this.prisma.question.update({
      where: { id },
      data: dto.options
        ? { ...dto, options: dto.options as any }
        : (dto as any),
    });
  }

  async deleteQuestion(id: string) {
    const question = await this.prisma.question.findUnique({
      where: { id },
    });
    if (!question) throw new NotFoundException('Pregunta no encontrada');

    await this.prisma.question.delete({ where: { id } });
    return { message: 'Pregunta eliminada correctamente' };
  }

  // ==================== TAKE EVALUATION ====================

  async getEvaluationForUser(evaluationId: string, userId: string) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id: evaluationId },
      include: {
        questions: {
          orderBy: { order: 'asc' },
          select: {
            id: true,
            question: true,
            options: true,
            order: true,
            // NO incluir correctId para el usuario
          },
        },
        theme: { select: { id: true, title: true, slug: true } },
      },
    });

    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');

    // Verificar si ya completó la evaluación
    const existingResult = await this.prisma.evaluationResult.findUnique({
      where: { userId_evaluationId: { userId, evaluationId } },
    });

    return {
      ...evaluation,
      alreadyCompleted: !!existingResult,
      previousResult: existingResult
        ? { score: existingResult.score, passed: existingResult.passed }
        : null,
    };
  }

  async submitEvaluation(
    evaluationId: string,
    userId: string,
    dto: SubmitEvaluationDto,
  ) {
    const evaluation = await this.prisma.evaluation.findUnique({
      where: { id: evaluationId },
      include: { questions: true },
    });

    if (!evaluation) throw new NotFoundException('Evaluación no encontrada');

    // Verificar si ya completó la evaluación
    const existingResult = await this.prisma.evaluationResult.findUnique({
      where: { userId_evaluationId: { userId, evaluationId } },
    });

    if (existingResult) {
      throw new BadRequestException('Ya has completado esta evaluación');
    }

    // Calcular puntuación
    let correctAnswers = 0;
    const totalQuestions = evaluation.questions.length;

    for (const answer of dto.answers) {
      const question = evaluation.questions.find(
        (q) => q.id === answer.questionId,
      );
      if (question && question.correctId === answer.selectedId) {
        correctAnswers++;
      }
    }

    const score = Math.round((correctAnswers / totalQuestions) * 100);
    const passed = score >= evaluation.passingScore;

    // Guardar resultado
    const result = await this.prisma.evaluationResult.create({
      data: {
        userId,
        evaluationId,
        score,
        passed,
        answers: dto.answers as any,
        timeTaken: dto.timeTaken,
      },
      include: {
        evaluation: {
          select: {
            title: true,
            passingScore: true,
            theme: { select: { id: true, title: true, slug: true } },
          },
        },
      },
    });

    return {
      ...result,
      correctAnswers,
      totalQuestions,
      message: passed
        ? '¡Felicitaciones! Has aprobado la evaluación.'
        : 'No has alcanzado el puntaje mínimo. Puedes revisar el contenido y volver a intentarlo.',
    };
  }

  async getUserResults(userId: string) {
    return this.prisma.evaluationResult.findMany({
      where: { userId },
      include: {
        evaluation: {
          select: {
            title: true,
            passingScore: true,
            theme: { select: { id: true, title: true } },
          },
        },
      },
      orderBy: { completedAt: 'desc' },
    });
  }
}

