  Inject,
  UnauthorizedException,
} from '@nestjs/common';
import { REQUEST } from '@nestjs/core';
import { ConfigService } from '@nestjs/config';
import { ClsService } from 'nestjs-cls';
import { PrismaService } from '../../prisma/prisma.service';
import { EmailService } from '../email/email.service';
import { StorageService } from '../storage/storage.service';
import { MercadoPagoConfig, Preference, Payment } from 'mercadopago';
import * as crypto from 'crypto';
import type { Request } from 'express';
import { CreateCheckoutDto } from './dto';

@Injectable()
export class PaymentsService {
  private readonly logger = new Logger(PaymentsService.name);
  private mp: MercadoPagoConfig | null = null;
  private preference: Preference | null = null;
  private paymentClient: Payment | null = null;

  constructor(
    private cls: ClsService,
    private prisma: PrismaService,
    private config: ConfigService,
    private emailService: EmailService,
    private storageService: StorageService,
  ) {
    // Initialization moved to async method
  }

  private getTenantId(): string {
    return this.cls.get('tenantId') || 'default';
  }

  private async getMercadoPagoConfig() {
    try {
      const setting = await this.prisma.secure.systemSetting.findFirst({
        where: { tenantId: this.getTenantId(), key: 'MERCADOPAGO_CONFIG' },
      });

      if (!setting || !setting.value) {
        this.logger.error('MERCADOPAGO_CONFIG not found in DB');
        throw new InternalServerErrorException('Payment configuration missing');
      }

      const config =
        typeof setting.value === 'string'
          ? JSON.parse(setting.value)
          : setting.value;

      // Validar que tenga lo necesario
      if (!config.accessToken || !config.publicKey) {
        this.logger.error('Invalid MERCADOPAGO_CONFIG structure');
        throw new InternalServerErrorException('Invalid payment configuration');
      }

      return config;
    } catch (error) {
      this.logger.error('Error fetching Mercado Pago config', error);
      throw new InternalServerErrorException(
        'Could not load payment configuration',
      );
    }
  }

  private async getTenantCurrency(): Promise<string> {
    try {
      const setting = await this.prisma.secure.systemSetting.findFirst({
        where: { tenantId: this.getTenantId(), key: 'TENANT_CONFIG' },
      });

      if (!setting || !setting.value) {
        this.logger.warn('TENANT_CONFIG not found, using default currency COP');
        return 'COP';
      }

      const config =
        typeof setting.value === 'string'
          ? JSON.parse(setting.value)
          : setting.value;

      return config.currency || 'COP';
    } catch (error) {
      this.logger.error('Error fetching tenant currency', error);
      return 'COP'; // Fallback
    }
  }

  private async initMercadoPago() {
    if (this.mp) return; // Ya inicializado

    const config = await this.getMercadoPagoConfig();
    this.mp = new MercadoPagoConfig({ accessToken: config.accessToken });
    this.preference = new Preference(this.mp);
    this.paymentClient = new Payment(this.mp);

    return config; // Retornamos config por si necesitamos webhookSecret u otros
  }

  async verifyWebhookSignature(
    xSignature: string,
    xRequestId: string,
    dataId: string,
  ): Promise<boolean> {
    let secret = '';
    try {
      const config = await this.getMercadoPagoConfig();
      secret = config.webhookSecret;
    } catch (e) {
      this.logger.warn('Could not load MP config for signature verification');
    }

    if (!secret) {
      // Fallback to env or allow if logic dictates (User requirement: eliminate env, but keep robustness)
      secret = this.config.get<string>('MP_WEBHOOK_SECRET') || '';
    }

    if (!secret) {
      this.logger.error(
        'MP_WEBHOOK_SECRET not configured (DB or Env). Rejecting webhook for security.',
      );
      return false;
    }

    if (!xSignature || !xRequestId || !dataId) {
      return false;
    }

    try {
      // x-signature format: ts=...;v1=...
      const parts = xSignature.split(';');
      let ts = '';
      let v1 = '';

      parts.forEach((part) => {
        const [key, value] = part.split('=');
        if (key === 'ts') ts = value;
        if (key === 'v1') v1 = value;
      });

      const manifest = `id:${dataId};request-id:${xRequestId};ts:${ts};`;

      const hmac = crypto.createHmac('sha256', secret);
      hmac.update(manifest);
      const sha = hmac.digest('hex');

      return sha === v1;
    } catch (error) {
      this.logger.error('Error verifying signature', error);
      return false;
    }
  }

  // ==================== SUBSCRIPTIONS ====================

  async createSubscriptionCheckout(
    userId: string,
    email?: string,
    frontUrl?: string,
  ) {
    await this.initMercadoPago();

    if (!this.preference) {
      throw new BadRequestException('Mercado Pago no está configurado');
    }

    const user = await this.prisma.secure.user.findUnique({
      where: { id: userId },
      include: { subscription: true },
    });

    if (!user) throw new NotFoundException('Usuario no encontrado');

    // Si ya tiene suscripción activa, no permitir crear otra
    if (user.subscription?.status === 'ACTIVE') {
      throw new BadRequestException('Ya tienes una suscripción activa');
    }

    const frontendUrl =
      frontUrl ||
      this.config.get<string>('FRONTEND_URL') ||
      'http://localhost:3000';
    const subscriptionPrice = 15; // USD - Precio mensual
    const currency = await this.getTenantCurrency();

    // Crear preferencia de pago en Mercado Pago
    const preferenceData = {
      items: [
        {
          id: 'subscription-monthly',
          title: 'Suscripción Premium - Mauro Mera',
          description:
            'Acceso completo a todos los cursos, contenido premium y evaluaciones',
          quantity: 1,
          unit_price: subscriptionPrice,
          currency_id: currency,
        },
      ],
      payer: {
        email: email || user.email,
      },
      back_urls: {
        success: `${frontendUrl}/suscripcion/exito`,
        failure: `${frontendUrl}/suscripcion/error`,
        pending: `${frontendUrl}/suscripcion/pendiente`,
      },
      auto_return: 'approved' as const,
      notification_url: `${this.config.get('API_PUBLIC_URL') || this.config.get('API_URL') || 'http://localhost:3001'}/api/payments/webhook?tenantId=${this.getTenantId()}`,
      external_reference: userId,
      metadata: {
        userId,
        type: 'subscription',
      },
    };

    try {
      const response = await this.preference.create({ body: preferenceData });

      // Crear o actualizar registro de suscripción como pendiente
      await this.prisma.subscription.upsert({
        where: { userId },
        create: {
          userId,
          status: 'PENDING',
        },
        update: {
          status: 'PENDING',
        },
      });

      return {
        preferenceId: response.id,
        initPoint: response.init_point,
        sandboxInitPoint: response.sandbox_init_point,
      };
    } catch (error) {
      this.logger.error('Error creating subscription preference', error);
      throw new BadRequestException('Error al crear la preferencia de pago');
    }
  }

  async cancelSubscription(userId: string) {
    const subscription = await this.prisma.subscription.findUnique({
      where: { userId },
    });

    if (!subscription) {
      throw new NotFoundException('No tienes una suscripción');
    }

    if (subscription.status !== 'ACTIVE') {
      throw new BadRequestException('La suscripción ya está cancelada');
    }

    // Actualizar estado a CANCELLED
    await this.prisma.subscription.update({
      where: { userId },
      data: { status: 'CANCELLED' },
    });

    return { message: 'Suscripción cancelada correctamente' };
  }

  async getSubscriptionStatus(userId: string) {
    const subscription = await this.prisma.subscription.findUnique({
      where: { userId },
    });

    if (!subscription) {
      return { hasSubscription: false, status: null };
    }

    return {
      hasSubscription: true,
      status: subscription.status,
      startDate: subscription.startDate,
      endDate: subscription.endDate,
    };
  }

  // ==================== PRODUCT PURCHASES ====================

  async createProductCheckout(dto: CreateCheckoutDto, tenantId: string) {
    // 2. Credenciales Multi-tenant
    const setting = await this.prisma.secure.systemSetting.findFirst({
      where: { tenantId, key: 'MERCADOPAGO_CONFIG' },
    });

    if (!setting || !setting.value) {
      throw new BadRequestException(
        'El vendedor no ha configurado MercadoPago',
      );
    }

    const config =
      typeof setting.value === 'string'
        ? JSON.parse(setting.value)
        : setting.value;
    const accessToken = config.accessToken;

    if (!accessToken) {
      throw new BadRequestException(
        'El vendedor no ha configurado MercadoPago',
      );
    }

    // 3. Instanciación Dinámica (Aislado por Request Multi-tenant)
    const client = new MercadoPagoConfig({ accessToken });
    const preference = new Preference(client);

    const frontendUrl =
      dto.frontUrl ||
      this.config.get<string>('FRONTEND_URL') ||
      'http://localhost:3000';
    const currency = await this.getTenantCurrency();

    // 1. Seguridad de Precios / Fetch Variants
    const preferenceItems: any[] = [];
    let totalAmount = 0;

    if (!dto.items || dto.items.length === 0) {
      throw new BadRequestException('El carrito está vacío');
    }

    // Batch fetch variants
    const variantIds = dto.items.map((i) => i.variantId);
    const variants = await this.prisma.secure.productVariant.findMany({
      where: { id: { in: variantIds } },
      include: { product: true },
    });
    const variantMap = new Map(variants.map((v) => [v.id, v]));

    // Batch fetch modifiers
    const modifierIds = dto.items.flatMap(
      (i) => i.modifiers?.map((m) => m.modifierId) || [],
    );
    const modifiers =
      modifierIds.length > 0
        ? await this.prisma.secure.modifier.findMany({
            where: { id: { in: modifierIds } },
          })
        : [];
    const modifierMap = new Map(modifiers.map((m) => [m.id, m]));

    for (const item of dto.items) {
      const variant = variantMap.get(item.variantId);

      if (!variant)
        throw new NotFoundException(
          `Variante no encontrada: ${item.variantId}`,
        );
      if (!variant.product.published)
        throw new BadRequestException(
          `Producto no disponible: ${variant.product.name}`,
        );

      let unitPrice = Number(variant.price);
      let description = variant.name !== 'Standard' ? variant.name : '';

      // Add modifier prices
      if (item.modifiers && item.modifiers.length > 0) {
        const modDescriptions: string[] = [];
        for (const modItem of item.modifiers) {
          const mod = modifierMap.get(modItem.modifierId);
          if (mod) {
            unitPrice += Number(mod.priceAdjustment) * modItem.quantity;
            modDescriptions.push(`${mod.name} (x${modItem.quantity})`);
          }
        }
        if (modDescriptions.length > 0) {
          description = description
            ? `${description} - ${modDescriptions.join(', ')}`
            : modDescriptions.join(', ');
        }
      }

      totalAmount += unitPrice * item.quantity;

      preferenceItems.push({
        id: variant.id,
        title: variant.product.name,
        description: description || undefined,
        quantity: item.quantity,
        unit_price: unitPrice,
        currency_id: currency,
        picture_url:
          variant.product.images?.[0] || variant.product.digitalFileUrl,
      });
    }

    // 4. Creación de Preferencia (Metadata Crítico)
    const metadata = {
      tenant_id: tenantId, // MercadoPago prefiere snake_case en custom objects a veces o strings simples
      type: 'order',
      items_json: JSON.stringify(dto.items),
      customer_name: dto.customer?.name || '',
      customer_email: dto.customer?.email || '',
      customer_phone: dto.customer?.phone || '',
      user_id: dto.customer?.userId || '',
      address: dto.customer?.address || '',
      city: dto.customer?.city || '',
      lng: dto.customer?.lng?.toString() || '',
      existing_order_id: dto.existingOrderId || '',
      identification: dto.customer?.identification || '',
    };

    const apiUrl =
      this.config.get<string>('API_PUBLIC_URL') ||
      this.config.get<string>('API_URL') ||
      'http://localhost:3001';
    const notificationUrl = `${apiUrl}/api/payments/webhook?tenantId=${tenantId}`;

    const fullName = (dto.customer?.name || 'Cliente').trim();
    const nameParts = fullName.split(/\s+/);
    const firstName = nameParts[0];
    const lastName =
      nameParts.length > 1 ? nameParts.slice(1).join(' ') : 'Cliente';

    const preferenceData = {
      items: preferenceItems,
      payer: {
        name: firstName,
        surname: lastName,
        email: dto.customer?.email || `invitado@${tenantId}.com`,
        phone: dto.customer?.phone
          ? {
              area_code: '57',
              number: dto.customer.phone.replace(/\D/g, ''),
            }
          : undefined,
        identification: dto.customer?.identification
          ? {
              type: 'CC',
              number: dto.customer.identification.replace(/\D/g, ''),
            }
          : undefined,
        address: dto.customer?.address
          ? {
              street_name: dto.customer.address,
              zip_code: dto.customer.city || '',
            }
          : undefined,
      },
      back_urls: {
        success: `${frontendUrl}/checkout/success`,
        failure: `${frontendUrl}/checkout/failure`,
        pending: `${frontendUrl}/checkout/pending`,
      },
      auto_return: 'approved' as const,
      notification_url: notificationUrl,
      metadata,
    };

    try {
      const response = await preference.create({ body: preferenceData });
      return {
        init_point: response.init_point,
        sandbox_init_point: response.sandbox_init_point,
        preferenceId: response.id,
        totalAmount,
      };
    } catch (error) {
      this.logger.error(
        'Error creating product preference via MercadoPago',
        error,
      );
      throw new BadRequestException('Error al iniciar el pago con MercadoPago');
    }
  }

  // ==================== WEBHOOKS ====================

  async handleWebhook(type: string, dataId: string) {
    this.logger.log(`Webhook received: type=${type}, data.id=${dataId}`);

    if (type !== 'payment') {
      return { status: 'ignored', reason: 'not a payment notification' };
    }

    return this.processWebhook(dataId);
  }

  private async processWebhook(dataId: string) {
    // En este punto aún no sabemos el tenantId seguro.
    // 1. Debemos hacer un fetch global a todas las configs o iterar si no tenemos el tenantId a priori.
    // Dado que MercadoPago envía la notificación globalmente, a menos que el webhook URL tenga ?tenantId=...
    // Aquí asumimos que el Request inicial lo trajo, PERO si no lo trae, buscaremos el tenant iterativamente o de la metadata si logramos desencriptar.

    // Estrategia segura: Instanciar MP "a ciegas" aquí es imposible sin accessToken.
    // PERO si el controlador forzó la inyección de tenantId via query param (ej: /webhook?tenantId=xxx),
    // this.getTenantId() funcionará. Si no, tenemos un problema de diseño en MP oauth vs access_token.
    // Asumiendo que tenantId viene por URL query (`this.getTenantId()`) o fue inyectado por el interceptor:

    const tenantId = this.getTenantId();

    if (tenantId === 'default') {
      this.logger.error(
        `Webhook rejected: Unable to determine tenant for data.id=${dataId}`,
      );
      return { status: 'error', reason: 'tenant not identified in webhook' };
    }

    const resolvedTenantId = tenantId;

    try {
      // 1. Recuperar Credenciales
      const setting = await this.prisma.secure.systemSetting.findFirst({
        where: { tenantId: resolvedTenantId, key: 'MERCADOPAGO_CONFIG' },
      });

      if (!setting || !setting.value) {
        return {
          status: 'error',
          reason: 'Mercado Pago configuration missing',
        };
      }

      const config =
        typeof setting.value === 'string'
          ? JSON.parse(setting.value)
          : setting.value;
      const accessToken = config.accessToken;

      if (!accessToken) {
        return { status: 'error', reason: 'Mercado Pago not configured' };
      }

      // 2. Consultar la Fuente de Verdad (MP API)
      const client = new MercadoPagoConfig({ accessToken });
      const paymentClient = new Payment(client);

      const paymentData = await paymentClient.get({ id: dataId });

      if (!paymentData) {
        this.logger.warn(`Payment ${dataId} not found`);
        return { status: 'error', reason: 'payment not found' };
      }

      const status = paymentData.status;
      const metadata = paymentData.metadata;

      this.logger.log(
        `Payment status: ${status}, metadata_type: ${metadata?.type}`,
      );

      // 3. Verificar Estado
      if (status === 'approved') {
        const paymentType = metadata?.type;

        if (paymentType === 'subscription') {
          // Logica de suscripcion (Legacy/Original)
          const userId = metadata?.userId;
          if (userId) {
            await this.activateSubscription(
              userId,
              dataId,
              paymentData.payer?.id?.toString(),
            );
          }
        } else if (paymentType === 'order') {
          // 4. Extraer Metadata
          const itemsJson = metadata.items_json;
          const customerEmail = metadata.customer_email;
          const customerName = metadata.customer_name;
          const customerPhone = metadata.customer_phone;
          const metaTenantId = metadata.tenant_id;
          const address = metadata.address;
          const city = metadata.city;
          const lat = metadata.lat ? parseFloat(metadata.lat) : undefined;
          const lng = metadata.lng ? parseFloat(metadata.lng) : undefined;
          const existingOrderId = metadata.existing_order_id;
          const identification = metadata.identification;

          // Anti-IDOR / Spoofing check
          if (metaTenantId !== resolvedTenantId) {
            this.logger.error(
              `Tenant mismatch in webhook. Expected ${resolvedTenantId}, got ${metaTenantId}`,
            );
            return {
              status: 'error',
              reason: 'tenant mismatch security error',
            };
          }

          let items: any[] = [];
          try {
            items =
              typeof itemsJson === 'string' ? JSON.parse(itemsJson) : itemsJson;
          } catch (e) {
            this.logger.error('Failed to parse items_json from MP metadata', e);
          }

          // Avoid duplicate processing by checking if an Order with this mpPaymentId already exists
          const existingOrder = await this.prisma.secure.order.findFirst({
            where: { mpPaymentId: dataId, tenantId: resolvedTenantId },
          });

          if (existingOrder) {
            this.logger.log(`Order for payment ${dataId} already processed.`);
            return { status: 'processed' };
          }

          // 5. Creación de la Orden (Prisma Transaction)
          await this.prisma.$transaction(async (tx) => {
            let totalAmount = 0;
            const orderItemsData: any[] = [];
            const digitalItemsDispatch: any[] = [];

            // Batch fetch all modifiers involved
            const allModifierIds = items.flatMap(
              (i: any) => i.modifiers?.map((m: any) => m.modifierId) || [],
            );
            const allModifiers =
              allModifierIds.length > 0
                ? await tx.modifier.findMany({
                    where: { id: { in: allModifierIds } },
                  })
                : [];
            const modifierMap = new Map(allModifiers.map((m) => [m.id, m]));

            for (const item of items) {
              const variant = await tx.productVariant.findUnique({
                where: { id: item.variantId },
                include: { product: true },
              });

              if (!variant) continue;

              let itemPrice = Number(variant.price);
              const itemModifiersData: any[] = [];

              if (item.modifiers && item.modifiers.length > 0) {
                for (const modItem of item.modifiers) {
                  const mod = modifierMap.get(modItem.modifierId);
                  if (mod) {
                    itemPrice += Number(mod.priceAdjustment) * modItem.quantity;
                    itemModifiersData.push({
                      modifierId: mod.id,
                      modifierName: mod.name,
                      priceAdjustment: mod.priceAdjustment,
                      quantity: modItem.quantity,
                    });
                  }
                }
              }

              totalAmount += itemPrice * item.quantity;

              orderItemsData.push({
                variantId: variant.id,
                quantity: item.quantity,
                price: itemPrice,
                productName: variant.product.name,
                variantName: variant.name !== 'Standard' ? variant.name : null,
                isPaid: true,
                modifiers: {
                  create: itemModifiersData,
                },
              });

              if (variant.product.productType === 'DIGITAL') {
                digitalItemsDispatch.push(variant.product);
              }
            }

            if (orderItemsData.length === 0) {
              throw new Error('No valid items found for order');
            }

            let newOrder;

            if (existingOrderId) {
              const preExisting = await tx.order.findUnique({
                where: { id: existingOrderId },
              });

              if (!preExisting) {
                this.logger.error(
                  `Order ${existingOrderId} not found for payment ${dataId}`,
                );
                throw new Error(`Order ${existingOrderId} not found`);
              }

              newOrder = await tx.order.update({
                where: { id: existingOrderId },
                data: {
                  status: 'APPROVED',
                  mpPaymentId: dataId,
                  // Actualizar envío en caso de haberlo incluido
                  shippingData: address
                    ? {
                        address,
                        city,
                        lat,
                        lng,
                      }
                    : (preExisting.shippingData ?? undefined),
                  customerEmail: customerEmail || preExisting.customerEmail,
                  identification: identification || preExisting.identification,
                },
              });

              await tx.orderItem.updateMany({
                where: { orderId: existingOrderId },
                data: { isPaid: true },
              });
            } else {
              // Generar numero de orden
              const orderNumber = `ORD-${Date.now().toString().slice(-6)}-${Math.floor(Math.random() * 100)}`;

              newOrder = await tx.order.create({
                data: {
                  tenantId: resolvedTenantId,
                  orderNumber,
                  totalAmount,
                  status: 'APPROVED',
                  orderType: 'DELIVERY', // o 'DINE_IN' según modelo, asumiendo e-commerce
                  mpPaymentId: dataId,
                  customerName,
                  customerPhone,
                  customerEmail,
                  identification,
                  notes: '',
                  shippingData: address
                    ? {
                        address,
                        city,
                        lat,
                        lng,
                      }
                    : undefined,
                  items: {
                    create: orderItemsData,
                  },
                },
              });
            }

            this.logger.log(
              `Order ${newOrder.orderNumber} created successfully via Webhook`,
            );

            // 6. Despacho Digital (Lógica)
            if (digitalItemsDispatch.length > 0 && customerEmail) {
              this.logger.log(
                `Dispatching ${digitalItemsDispatch.length} digital items to ${customerEmail}`,
              );

              const dispatchLinks: {
                productName: string;
                downloadUrl: string;
              }[] = [];

              for (const product of digitalItemsDispatch) {
                if (product.digitalFileUrl) {
                  try {
                    // Generar Pre-Signed URL con 24 horas de validez (86400 segundos)
                    const downloadUrl =
                      await this.storageService.getPresignedUrl(
                        product.digitalFileUrl,
                        86400,
                      );
                    dispatchLinks.push({
                      productName: product.name,
                      downloadUrl,
                    });
                  } catch (err) {
                    this.logger.error(
                      `Error generating presigned URL for ${product.name}`,
                      err,
                    );
                  }
                }
              }

              if (dispatchLinks.length > 0) {
                // Ejecutar envío de email SIN await dentro del transaction.
                // Usamos un `.catch` para no bloquear el Event Loop ni revertir el commit de Prisma si falla el SMTP.
                this.emailService
                  .sendDigitalDelivery(
                    customerEmail,
                    customerName || 'Cliente',
                    dispatchLinks,
                  )
                  .then((success) => {
                    if (success) {
                      this.logger.log(
                        `Digital delivery email sent to ${customerEmail}`,
                      );
                    } else {
                      this.logger.error(
                        `Failed to send digital delivery email to ${customerEmail}`,
                      );
                    }
                  })
                  .catch((e) => {
                    this.logger.error(
                      `Unhandled error sending digital delivery email to ${customerEmail}`,
                      e,
                    );
                  });
              }
            }
          });
        }
      }

      return { status: 'processed' };
    } catch (error) {
      this.logger.error('Error processing webhook', error);
      return { status: 'error', reason: 'processing failed' };
    }
  }

  private async activateSubscription(
    userId: string,
    mpPaymentId: string,
    mpPayerId?: string,
  ) {
    const startDate = new Date();
    const endDate = new Date();
    endDate.setMonth(endDate.getMonth() + 1); // 1 mes de suscripción

    await this.prisma.subscription.upsert({
      where: { userId },
      create: {
        userId,
        status: 'ACTIVE',
        mpSubscriptionId: mpPaymentId,
        mpPayerId: mpPayerId,
        startDate,
        endDate,
      },
      update: {
        status: 'ACTIVE',
        mpSubscriptionId: mpPaymentId,
        mpPayerId: mpPayerId,
        startDate,
        endDate,
      },
    });

    this.logger.log(`Subscription activated for user ${userId}`);

    // Send confirmation email (non-blocking - don't fail if email fails)
    try {
      const user = await this.prisma.secure.user.findUnique({
        where: { id: userId },
        select: { email: true, name: true },
      });

      if (user) {
        await this.emailService.sendSubscriptionSuccessEmail(
          user.email,
          user.name || 'Usuario',
          'Suscripción Premium Mensual',
          endDate,
        );
      }
    } catch (emailError) {
      this.logger.error('Error sending subscription email:', emailError);
      // Continue - don't fail the transaction if email fails
    }
  }

  private async approveOrder(orderId: string, mpPaymentId: string) {
    // 1. Update Order Status
    const tenantId = this.getTenantId();
    const order = await this.prisma.secure.order.findUnique({
      where: { id: orderId }, // Si tienes @@unique compuesto, asegúrate de ajustarlo aquí (ej. tenantId_id)
      include: { user: true, items: true },
    });

    // Anti-IDOR Check: Validar que la orden pertenece al tenant
    if (order && order.tenantId !== tenantId) {
      this.logger.error(
        `Security Breach Attempt: Order ${orderId} does not belong to tenant ${tenantId}`,
      );
      return;
    }

    if (!order || order.status === 'APPROVED' || order.status === 'DELIVERED') {
      this.logger.warn(`Order ${orderId} already approved or not found.`);
      return;
    }

    await this.prisma.secure.order.update({
      where: { id: orderId }, // Asume que ID es primary key aislada, el check previo protege el Row-Level
      data: {
        status: 'APPROVED',
        mpPaymentId,
      },
    });

    this.logger.log(`Order ${orderId} approved.`);

    // 2. Reduce Stock (if physical/tracked)
    // Note: For now we are focusing on digital flow, but good to add TODO for stock management
    // await this.reduceStock(order.items);

    // 3. Send Confirmation Email
    try {
      // We can send a generic summary email, or 1 email per digital item if needed.
      // For now, let's send 1 email per digital item to match legacy behavior, or a new summary email.
      // Let's stick to the plan: DigitalPurchaseEmail (generic).

      // If order has multiple digital items, we might spam user. Ideally create OrderConfirmationEmail.
      // But to minimize scope creep, let's send DigitalPurchaseEmail for the first item found or loop.
      // Let's loop for now to ensure delivery of all links.

      // Batch fetch: single query replaces N findUnique calls
      const variantIds = order.items.map((i) => i.variantId);
      const variants = await this.prisma.secure.productVariant.findMany({
        where: { id: { in: variantIds } },
        include: { product: true },
      });
      const variantMap = new Map(variants.map((v) => [v.id, v]));

      for (const item of order.items) {
        const variant = variantMap.get(item.variantId);

        if (variant && variant.product.productType === 'DIGITAL') {
          if (order.user?.email) {
            await this.emailService.sendDigitalPurchaseEmail(
              order.user.email,
              order.user.name || order.customerName || 'Cliente',
              item.productName,
              variant.product.slug,
            );
          } else {
            this.logger.warn(
              `No se pudo enviar email digital para la orden ${orderId}: No hay email disponible.`,
            );
          }
        }
      }
    } catch (e) {
      this.logger.error(`Error sending order email for ${orderId}`, e);
    }
  }

  // Admin: Assign manual subscription
  async assignManualSubscription(userId: string, days = 30) {
    const startDate = new Date();
    const endDate = new Date();
    endDate.setDate(endDate.getDate() + days);

    await this.prisma.subscription.upsert({
      where: { userId },
      create: {
        userId,
        status: 'ACTIVE',
        mpSubscriptionId: 'MANUAL_ASSIGNMENT',
        startDate,
        endDate,
      },
      update: {
        status: 'ACTIVE',
        mpSubscriptionId: 'MANUAL_ASSIGNMENT',
        startDate,
        endDate,
      },
    });

    this.logger.log(
      `Manual subscription assigned to user ${userId} for ${days} days`,
    );
    return { message: 'Suscripción asignada correctamente' };
  }

  // ==================== USER SUBSCRIPTION CHECK ====================

  async hasActiveSubscription(userId: string): Promise<boolean> {
    const subscription = await this.prisma.subscription.findUnique({
      where: { userId },
    });
    return subscription?.status === 'ACTIVE';
  }

  // ==================== ADMIN ====================

  async getPaymentStats() {
    const [activeSubscriptions, totalEbookPurchases, pendingSubscriptions] =
      await Promise.all([
        this.prisma.subscription.count({ where: { status: 'ACTIVE' } }),
        this.prisma.purchase.count({ where: { status: 'approved' } }),
        this.prisma.subscription.count({ where: { status: 'PENDING' } }),
      ]);

    const recentSubscriptions = await this.prisma.subscription.findMany({
      where: { status: 'ACTIVE' },
      take: 10,
      orderBy: { startDate: 'desc' },
      include: { user: { select: { email: true, name: true } } },
    });

    return {
      activeSubscriptions,
      totalEbookPurchases,
      pendingSubscriptions,
      recentSubscriptions,
    };
  }
}

import { Injectable, NotFoundException, Inject } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import type { Cache } from 'cache-manager';
import { PrismaService } from '../../prisma/prisma.service';

@Injectable()
export class RestaurantService {
  constructor(
    private prisma: PrismaService,
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
  ) {}

  private async getTenantIdBySlug(slug: string): Promise<string> {
    const tenant = await this.prisma.secure.tenant.findUnique({
      where: { slug },
      select: { id: true },
    });
    if (!tenant) {
      throw new NotFoundException('Restaurant not found');
    }
    return tenant.id;
  }

  async getPublicMenu(slugOrId: string) {
    // 0. Check Cache
    const cacheKey = `public_menu:${slugOrId}`;

    // 1. Find Tenant (Polymorphic: ID or Slug)
    let tenant: any = null;

    // Try lookup by ID first (likely coming from Edge Proxy via custom domain)
    try {
      tenant = await this.prisma.secure.tenant.findUnique({
        where: { id: slugOrId },
        include: { brandSettings: true },
      });
    } catch (e) {
      // Probably not a valid UUID, ignore and try slug
    }

    // Fallback to Slug lookup
    if (!tenant) {
      tenant = await this.prisma.secure.tenant.findUnique({
        where: { slug: slugOrId },
        include: { brandSettings: true },
      });
    }

    if (!tenant) {
      throw new NotFoundException('Restaurant not found');
    }

    const tenantId = tenant.id;

    // 2. Find Categories (filtered by tenant via products)
    const categories = await this.prisma.secure.category.findMany({
      where: {
        tenantId,
        products: {
          some: {
            product: {
              published: true,
              isAvailable: true,
            },
          },
        },
      },
      select: {
        id: true,
        name: true,
        slug: true,
      },
      orderBy: { name: 'asc' },
    });

    // 3. Find Products
    const products = await this.prisma.secure.product.findMany({
      where: {
        tenantId,
        published: true,
        isAvailable: true,
      },
      include: {
        variants: true,
        modifierGroups: {
          include: {
            modifiers: true,
          },
        },
        categories: {
          include: { category: true },
        },
        likes: true,
        comments: true,
      },
    });

    // 4. Fetch Tenant Config (SystemSetting modules: menu, contact, etc.)
    const systemSettings = await this.prisma.secure.systemSetting.findMany({
      where: { tenantId },
    });

    const tenantConfig = systemSettings.reduce(
      (acc, curr) => {
        acc[curr.key] = curr.value;
        return acc;
      },
      {} as Record<string, any>,
    );

    const contact = tenantConfig.contact || {};

    // 5. Transform Data for Public SDK
    const publicProducts = products.map((product) => ({
      id: product.id,
      name: product.name,
      description: product.description,
      slug: product.slug,
      images: product.images,
      basePrice: Number(product.basePrice),
      categories: product.categories.map((c) => ({
        id: c.category.id,
        name: c.category.name,
        slug: c.category.slug,
      })),
      variants: product.variants.map((v) => ({
        id: v.id,
        name: v.name,
        price: Number(v.price),
      })),
      modifierGroups: product.modifierGroups.map((mg) => ({
        id: mg.id,
        name: mg.name,
        minSelect: mg.minSelect,
        maxSelect: mg.maxSelect,
        modifiers: mg.modifiers.map((m) => ({
          id: m.id,
          name: m.name,
          price: Number(m.priceAdjustment),
          maxQuantity: m.stock ?? 99,
        })),
      })),
      // Social Features
      likesCount: product.likes.length,
      comments: product.comments
        .map((c) => ({
          id: c.id,
          userName: c.userName || 'Anónimo',
          content: c.content,
          createdAt: c.createdAt,
        }))
        .sort(
          (a, b) =>
            new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
        ),
    }));

    // 6. Build Response
    const response = {
      restaurant: {
        name: tenant.name || 'Restaurant',
        slug: tenant.slug,
        logo:
          tenant.brandSettings?.faviconUrl ||
          tenantConfig.menu?.logo ||
          tenant.design?.logo ||
          `https://api.dicebear.com/7.x/initials/svg?seed=${tenant.name}`,
        slogan:
          tenant.brandSettings?.tagline ||
          tenantConfig.menu?.slogan ||
          tenant.design?.slogan ||
          'Bienvenido a nuestro menú digital',
        coverVideo:
          tenant.brandSettings?.authBgUrl || tenant.design?.coverVideo || null,
        social: {
          instagram: contact.instagram
            ? `https://instagram.com/${contact.instagram.replace('@', '')}`
            : undefined,
          facebook: contact.facebook
            ? contact.facebook.startsWith('http')
              ? contact.facebook
              : `https://facebook.com/${contact.facebook}`
            : undefined,
          whatsapp: contact.whatsapp,
          twitter: contact.twitter
            ? `https://x.com/${contact.twitter.replace('@', '')}`
            : undefined,
          tiktok: contact.tiktok
            ? `https://tiktok.com/@${contact.tiktok.replace('@', '')}`
            : undefined,
          youtube: contact.youtube
            ? `https://youtube.com/${contact.youtube}`
            : undefined,
        },
        address: contact.address || null,
        phone: contact.whatsapp || null,
        orderTrackingEnabled: !!tenantConfig.orderTrackingEnabled,
      },
      categories,
      products: publicProducts,
    };

    // 7. Set Cache (5 minutes)
    await this.cacheManager.set(cacheKey, response, 300000);

    return response;
  }

  async toggleLike(slug: string, productId: string, userPhone: string) {
    // slug is used for public API identification but we don't need tenantId here
    // since productLike is scoped by productId which already belongs to a tenant
    const existingLike = await this.prisma.productLike.findUnique({
      where: {
        productId_userPhone: {
          productId,
          userPhone,
        },
      },
    });

    if (existingLike) {
      await this.prisma.productLike.delete({
        where: { id: existingLike.id },
      });
      return { liked: false };
    } else {
      await this.prisma.productLike.create({
        data: {
          productId,
          userPhone,
        },
      });
      return { liked: true };
    }
  }

  async addComment(
    slug: string,
    productId: string,
    userPhone: string,
    content: string,
    userName?: string,
  ) {
    const comment = await this.prisma.productComment.create({
      data: {
        productId,
        userPhone,
        content,
        userName,
        isApproved: true,
      },
    });

    return {
      id: comment.id,
      userName: comment.userName || 'Anónimo',
      content: comment.content,
      createdAt: comment.createdAt,
    };
  }

  async checkLikeStatus(slug: string, productId: string, userPhone: string) {
    const count = await this.prisma.productLike.count({
      where: {
        productId,
        userPhone,
      },
    });

    return { isLiked: count > 0 };
  }
}

import { Injectable, Logger, Inject } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import type { Cache } from 'cache-manager';
import { AiProvider, AiResponse } from './ai-provider.interface';
import { OpenAI } from 'openai';
import { PrismaService } from '../../../prisma/prisma.service';
import {
  RestaurantContextService,
  CatalogProduct,
} from '../services/restaurant-context.service';
import Fuse from 'fuse.js';

@Injectable()
export class OpenAiProvider implements AiProvider {
  private readonly logger = new Logger(OpenAiProvider.name);
  private openai: OpenAI;

  constructor(
    private readonly prisma: PrismaService,
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
    private readonly contextService: RestaurantContextService,
  ) {
    this.openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY,
    });
  }

  async generateResponse(
    tenantId: string,
    systemContext: string,
    history: { role: 'USER' | 'ASSISTANT'; content: string }[],
    userMessage: string,
    customerPhone?: string,
    tenantSlug?: string,
  ): Promise<AiResponse> {
    // Variable para rastrear si se generó un checkoutUrl durante tool calls
    let detectedCheckoutUrl: string | undefined;
    let deterministicReceipt: string | undefined;

    try {
      const messages: any[] = [
        { role: 'system', content: systemContext },
        ...history.map((msg) => ({
          role: msg.role === 'USER' ? 'user' : 'assistant',
          content: msg.content,
        })),
        { role: 'user', content: userMessage },
      ];

      const tools: any[] = [
        {
          type: 'function',
          function: {
            name: 'saveCustomerProfile',
            description:
              'Guarda o actualiza el perfil del cliente (nombre, dirección). Úsala cuando el cliente te proporcione sus datos.',
            parameters: {
              type: 'object',
              properties: {
                name: { type: 'string', description: 'Nombre del cliente' },
                address: {
                  type: 'string',
                  description: 'Dirección de envío completa',
                },
              },
              required: ['name'],
            },
          },
        },
        {
          type: 'function',
          function: {
            name: 'createSuggestedCart',
            description:
              'Crea un carrito de compras con los productos solicitados y genera el link de pago. IMPORTANTE: Usa esta herramienta SIEMPRE que el cliente decida pedir ciertos productos.',
            parameters: {
              type: 'object',
              properties: {
                items: {
                  type: 'array',
                  description: 'Lista de productos que el cliente quiere pedir',
                  items: {
                    type: 'object',
                    properties: {
                      name: {
                        type: 'string',
                        description:
                          'Nombre del producto tal como figura en el menú (no necesita ser exacto)',
                      },
                      quantity: {
                        type: 'integer',
                        description: 'Cantidad solicitada de este producto',
                      },
                      notes: {
                        type: 'string',
                        description:
                          'Instrucciones especiales o modificadores para este item. Ej: "sin cebolla", "extra queso", "bien cocida"',
                      },
                    },
                    required: ['name', 'quantity'],
                  },
                },
              },
              required: ['items'],
            },
          },
        },
      ];

      const completion = await this.openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages,
        temperature: 0.7,
        max_tokens: 400,
        tools,
        tool_choice: 'auto',
      });

      const responseMessage = completion.choices[0].message;

      // Check if OpenAI wanted to call a tool
      if (responseMessage.tool_calls && responseMessage.tool_calls.length > 0) {
        messages.push(responseMessage);

        for (const rawToolCall of responseMessage.tool_calls) {
          const toolCall = rawToolCall as any;

          if (toolCall.function.name === 'saveCustomerProfile') {
            this.logger.log(
              `[Tenant: ${tenantId}] OpenAI invocó la herramienta saveCustomerProfile para ${customerPhone}`,
            );
            let toolResponseText = '';
            try {
              const args = JSON.parse(toolCall.function.arguments);
              const { name, address } = args;

              const customer = await this.prisma.secure.waCustomer.upsert({
                where: {
                  tenantId_phone: { tenantId, phone: customerPhone || '' },
                },
                update: { name, address },
                create: { tenantId, phone: customerPhone || '', name, address },
              });

              toolResponseText = JSON.stringify({
                success: true,
                customerId: customer.id,
              });
            } catch (err) {
              this.logger.error(`Error en saveCustomerProfile: ${err.message}`);
              toolResponseText = JSON.stringify({
                error: 'Failed to save customer profile',
              });
            }

            messages.push({
              tool_call_id: toolCall.id,
              role: 'tool',
              name: toolCall.function.name,
              content: toolResponseText,
            });
          } else if (toolCall.function.name === 'getLatestOrderStatus') {
            this.logger.log(
              `[Tenant: ${tenantId}] OpenAI invocó la herramienta getLatestOrderStatus para ${customerPhone}`,
            );

            const order = await this.prisma.secure.order.findFirst({
              where: { customerPhone: customerPhone || '' },
              orderBy: { createdAt: 'desc' },
              select: { status: true, totalAmount: true, updatedAt: true },
            });

            let toolResponseText = '';
            if (order) {
              toolResponseText = JSON.stringify({
                status: order.status,
                total: order.totalAmount,
                updatedAt: order.updatedAt,
              });
            } else {
              toolResponseText = JSON.stringify({
                error: 'No active or past orders found for this customer.',
                actionRequired: `Invitar al cliente a su primer pedido usando amablemente el link del menú: https://${tenantSlug || 'demo'}.alvarolondoño.dev`,
              });
            }

            messages.push({
              tool_call_id: toolCall.id,
              role: 'tool',
              name: toolCall.function.name,
              content: toolResponseText,
            });
          } else if (toolCall.function.name === 'createSuggestedCart') {
            this.logger.log(
              `[Tenant: ${tenantId}] OpenAI invocó la herramienta createSuggestedCart para ${customerPhone}`,
            );
            let toolResponseText = '';

            try {
              const args = JSON.parse(toolCall.function.arguments);
              const requestedItems: {
                name: string;
                quantity: number;
                notes?: string;
              }[] = args.items || [];

              if (requestedItems.length === 0) {
                toolResponseText = JSON.stringify({
                  error: 'No items provided to create cart.',
                });
              } else {
                const foundProducts: any[] = [];
                const missingProducts: string[] = [];

                // Búsqueda Fuzzy con Fuse.js contra catálogo cacheado
                const catalog =
                  await this.contextService.getProductCatalog(tenantId);
                const fuse = new Fuse(catalog, {
                  keys: ['name'],
                  threshold: 0.4,
                  includeScore: true,
                  ignoreLocation: true,
                });

                for (const item of requestedItems) {
                  const results = fuse.search(item.name);

                  if (
                    results.length > 0 &&
                    results[0].score !== undefined &&
                    results[0].score <= 0.4
                  ) {
                    const match = results[0].item;
                    this.logger.log(
                      `[Fuzzy] "${item.name}" → "${match.name}" (score: ${results[0].score?.toFixed(3)})`,
                    );
                    foundProducts.push({
                      productId: match.id,
                      variantId: match.variantId,
                      title: match.name,
                      quantity: item.quantity,
                      price: match.basePrice,
                      productType: 'RESTAURANT',
                      imageSrc: match.images[0] || '',
                      notes: item.notes || undefined,
                    });
                  } else {
                    this.logger.warn(
                      `[Fuzzy] No match for "${item.name}" (best score: ${results[0]?.score?.toFixed(3) || 'N/A'})`,
                    );
                    missingProducts.push(item.name);
                  }
                }

                if (foundProducts.length === 0) {
                  toolResponseText = JSON.stringify({
                    error:
                      'None of the requested products were found in the active menu.',
                    actionRequired:
                      'Por favor, dile al cliente que esos productos no están disponibles y ofrécele alternativas del menú actual.',
                  });
                } else {
                  // ==========================================
                  // PERSISTIR CARRITO EN POSTGRESQL (WaCart)
                  // ==========================================
                  const cartId = `wa-${Date.now().toString(36)}-${Math.random().toString(36).substring(7)}`;

                  // Obtener perfil del cliente para hidratar el checkout
                  const customer =
                    await this.prisma.secure.waCustomer.findUnique({
                      where: {
                        tenantId_phone: {
                          tenantId,
                          phone: customerPhone || '',
                        },
                      },
                    });

                  const cartPayload = {
                    items: foundProducts,
                    customerData: customer
                      ? {
                          name: customer.name,
                          address: customer.address,
                          phone: customer.phone,
                          lat: customer.lat,
                          lng: customer.lng,
                        }
                      : {
                          phone: customerPhone,
                        },
                  };

                  const expiresAt = new Date();
                  expiresAt.setHours(expiresAt.getHours() + 24); // TTL 24 horas

                  this.logger.log(
                    `[CART_SAVE] === INICIO GUARDADO POSTGRESQL ===`,
                  );
                  this.logger.log(`[CART_SAVE] CartID: ${cartId}`);
                  this.logger.log(`[CART_SAVE] TenantID: ${tenantId}`);

                  try {
                    await this.prisma.secure.waCart.create({
                      data: {
                        id: cartId,
                        tenantId,
                        customerPhone: customerPhone || '',
                        cartData: cartPayload as any,
                        expiresAt,
                      },
                    });
                    this.logger.log(
                      `[CART_SAVE] ✅ Carrito guardado en Postgres exitosamente`,
                    );
                  } catch (err) {
                    this.logger.error(
                      `[CART_SAVE] ❌ FALLO guardando en Postgres: ${err.message}`,
                    );
                  }

                  this.logger.log(
                    `[CART_SAVE] === FIN GUARDADO POSTGRESQL ===`,
                  );

                  // Usamos el Punycode correcto (khb) para compatibilidad universal con móviles (Android/WhatsApp)
                  const checkoutUrl = `https://${tenantSlug || 'demo'}.xn--alvarolondoo-khb.dev/checkout?wa=${cartId}`;
                  detectedCheckoutUrl = checkoutUrl; // Guardar para retornar al processor

                  // Generar recibo determinista consultando la DB (deliveryFee)
                  const storeSettings =
                    await this.prisma.secure.storeSettings.findFirst({
                      where: { tenantId },
                    });
                  const deliveryFee = Number(storeSettings?.deliveryFee || 0);

                  let subtotal = 0;
                  let receiptText = `\n\n🧾 *Resumen de tu pedido:*\n`;

                  for (const item of foundProducts) {
                    const lineTotal = item.price * item.quantity;
                    subtotal += lineTotal;
                    receiptText += `- ${item.quantity}x ${item.title} ($${lineTotal.toLocaleString('es-CO')})\n`;
                  }

                  const total = subtotal + deliveryFee;
                  receiptText += `\n*Subtotal:* $${subtotal.toLocaleString('es-CO')}\n`;
                  receiptText += `*Domicilio:* $${deliveryFee.toLocaleString('es-CO')}\n`;
                  // Asteriscos envolviendo para hacer un markdown bold para WhatsApp de total final
                  receiptText += `\n*Total a pagar:* *$${total.toLocaleString('es-CO')}*`;

                  deterministicReceipt = receiptText;

                  toolResponseText = JSON.stringify({
                    success: true,
                    message: 'Cart created successfully.',
                    checkoutUrl,
                    itemsFound: foundProducts.map(
                      (p) => `${p.quantity}x ${p.title}`,
                    ),
                    itemsNotFound:
                      missingProducts.length > 0 ? missingProducts : undefined,
                  });
                }
              }
            } catch (err) {
              this.logger.error(
                `Error procesando createSuggestedCart: ${err.message}`,
              );
              toolResponseText = JSON.stringify({
                error: 'Internal error generating cart.',
              });
            }

            messages.push({
              tool_call_id: toolCall.id,
              role: 'tool',
              name: toolCall.function.name,
              content: toolResponseText,
            });
          }
        }

        // Segunda llamada a la IA con los datos de las herramientas
        const secondResponse = await this.openai.chat.completions.create({
          model: 'gpt-4o-mini',
          messages,
          temperature: 0.7,
        });

        const text =
          secondResponse.choices[0].message.content ||
          'Lo siento, no pude procesar tu solicitud tras revisar los datos.';

        // Adjuntar el recibo determinista si se creó un carrito en esta interacción
        let finalText = text;
        if (deterministicReceipt) {
          finalText += deterministicReceipt;
        }

        return { text: finalText, checkoutUrl: detectedCheckoutUrl };
      }

      return {
        text:
          responseMessage.content ||
          'Lo siento, no pude procesar tu solicitud.',
      };
    } catch (error) {
      this.logger.error(
        `Error en OpenAI para tenant ${tenantId}: ${error.message}`,
        error.stack,
      );
      throw new Error('Fallo al comunicarse con OpenAI');
    }
  }
}

import { Injectable, Inject, Logger } from '@nestjs/common';
import { CACHE_MANAGER } from '@nestjs/cache-manager';
import type { Cache } from 'cache-manager';
import { PrismaService } from '../../../prisma/prisma.service';

export interface CatalogProduct {
  id: string;
  name: string;
  basePrice: number;
  description: string | null;
  variantId: string;
  images: string[];
}

@Injectable()
export class RestaurantContextService {
  private readonly logger = new Logger(RestaurantContextService.name);

  constructor(
    private readonly prisma: PrismaService,
    @Inject(CACHE_MANAGER) private cacheManager: Cache,
  ) {}

  /**
   * Retorna el catálogo completo de productos activos del tenant,
   * cacheado en Redis. Usado por OpenAiProvider para búsqueda fuzzy con fuse.js.
   */
  async getProductCatalog(tenantId: string): Promise<CatalogProduct[]> {
    const cacheKey = `tenant:${tenantId}:product_catalog`;

    const cached = await this.cacheManager.get<string>(cacheKey);
    if (cached) {
      try {
        return JSON.parse(cached);
      } catch {
        this.logger.warn(
          `[Tenant: ${tenantId}] Catálogo corrupto en cache, regenerando...`,
        );
      }
    }

    this.logger.log(
      `[Tenant: ${tenantId}] Cache miss para catálogo de productos. Fetching DB...`,
    );

    const products = await this.prisma.secure.product.findMany({
      where: {
        productType: 'RESTAURANT',
        published: true,
        isAvailable: true,
      },
      select: {
        id: true,
        name: true,
        basePrice: true,
        description: true,
        images: true,
        variants: { select: { id: true }, take: 1 },
      },
    });

    const catalog: CatalogProduct[] = products.map((p) => ({
      id: p.id,
      name: p.name,
      basePrice: Number(p.basePrice),
      description: p.description || null,
      variantId: (p as any).variants[0]?.id || p.id,
      images: p.images || [],
    }));

    // Cache por 30 días (mismo TTL que el system prompt)
    await this.cacheManager.set(cacheKey, JSON.stringify(catalog), 2592000000);
    this.logger.log(
      `[Tenant: ${tenantId}] Catálogo de ${catalog.length} productos cacheado.`,
    );

    return catalog;
  }

  async buildSystemPrompt(
    tenantId: string,
    customerPhone?: string,
  ): Promise<string> {
    const cacheKey = `tenant:${tenantId}:menu_context`;

    // Intentar obtener del cache
    let menuContext = await this.cacheManager.get<string>(cacheKey);

    if (!menuContext) {
      this.logger.log(
        `[Tenant: ${tenantId}] Cache miss para menú. Construyendo prompt...`,
      );
      menuContext = await this.generateMenuContext(tenantId);

      // Guardar en cache por 30 días (2592000000 ms)
      await this.cacheManager.set(cacheKey, menuContext, 2592000000);
      this.logger.log(
        `[Tenant: ${tenantId}] Menú cacheado en Redis por 30 días.`,
      );
    }

    // El contexto dinámico del cliente NO se cachea porque cambia por usuario/conversación
    const customerContext = await this.buildCustomerContext(
      tenantId,
      customerPhone,
    );

    return `${menuContext}\n${customerContext}`;
  }

  private async generateMenuContext(tenantId: string): Promise<string> {
    // Obtener configuración del restaurante
    const storeSettings = await this.prisma.secure.storeSettings.findFirst({
      include: { tenant: { select: { slug: true } } },
    });
    const storeName = storeSettings?.storeName || 'Nuestro Restaurante';
    const tenantSlug = storeSettings?.tenant?.slug || 'demo';
    const deliveryFee = Number(storeSettings?.deliveryFee || 0);
    const deliveryFeeFormatted = deliveryFee > 0 ? `$${deliveryFee}` : 'Gratis';

    // Obtener menú (Categorías y Productos Activos)
    const categories = await this.prisma.secure.category.findMany({
      include: {
        products: {
          include: {
            product: true,
          },
        },
      },
    });

    let menuText = `=== MENÚ ===\n`;
    for (const cat of categories as any[]) {
      if (cat.products?.length === 0) continue;

      menuText += `\n[CATEGORÍA: ${cat.name}]\n`;
      for (const catProd of cat.products) {
        if (!catProd.product) continue;
        const p = catProd.product;
        if (!p.published || !p.isAvailable || p.productType !== 'RESTAURANT')
          continue;
        menuText += `- ${p.name}: $${p.basePrice} (${p.description || 'Sin descripción'})\n`;
      }
    }

    return `ROL Y PERSONALIDAD:
Eres un asistente virtual de ventas altamente eficiente, amable y profesional para el restaurante "${storeName}". 
Tu objetivo absoluto es atender dudas, tomar pedidos de forma natural y CONCRETAR VENTAS.
Tono: Conciso, conversacional, amigable (usa 1 o 2 emojis por mensaje). NUNCA suenes como un robot leyendo un manual.

=== CATÁLOGO DE PRODUCTOS ===
${menuText}

=== MANUAL DE OPERACIONES Y HERRAMIENTAS (REGLAS ESTRICTAS) ===

1. FLUJO DE VENTAS Y CARRITO (\`createSuggestedCart\`):
- Cuando el cliente confirme qué desea pedir (ej. "dame 2 hamburguesas"), DEBES invocar la herramienta \`createSuggestedCart\` INMEDIATAMENTE pasando los productos y cantidades.
- PROHIBIDO SIMULAR ESPERAS: NUNCA uses frases de relleno como "Un momento", "Procesando", "Voy a generar tu carrito" o "Dame un segundo". Las herramientas se ejecutan en milisegundos. Tu respuesta de texto debe ser directamente la confirmación rápida del pedido.
- PRECIOS Y MATEMÁTICAS: SÍ puedes informar el precio individual de un producto si el cliente lo pregunta directamente (ej. 'La hamburguesa cuesta $15,000'). SIN EMBARGO, está ESTRICTAMENTE PROHIBIDO sumar, calcular subtotales o dar el total final de un pedido. Si el cliente pide su cuenta o confirma el pedido, limítate a confirmar los productos amablemente; el sistema backend adjuntará automáticamente el recibo con el total matemático exacto debajo de tu mensaje.
- Si pide un producto que NO está en el menú, aclárale amablemente la confusión y sugiérele el producto más similar del catálogo.
- NUNCA incluyas links de pago en tu texto. El botón de pago ('Completar Pago 💳') aparecerá mágicamente debajo de tu mensaje gracias al sistema. Solo invita al cliente a hacer clic en el botón de abajo.

2. GESTIÓN DE CLIENTES (\`saveCustomerProfile\`):
- Si durante la conversación el cliente menciona su nombre o dirección, invoca \`saveCustomerProfile\` de forma silenciosa para asegurar que su perfil esté actualizado.
- Si el cliente quiere confirmar su orden pero el "Contexto del Cliente" indica que faltan sus datos, pídeselos natural y amablemente en un solo mensaje antes de cerrar la venta.

3. REGLAS DE NEGOCIO Y PRECIOS:
- Costo de Domicilio: ${deliveryFeeFormatted}. Al resumir el pedido antes del pago, menciona el subtotal y recuérdale explícitamente el costo de envío.
- Respeta estrictamente los precios del catálogo. Muestra el precio exacto mencionado.
- NUNCA enumeres ni imprimas el menú completo en el chat, es demasiado largo. Si el cliente quiere ver todo, envíale este enlace oficial: https://${tenantSlug}.alvarolondoño.dev

4. LÍMITES DEL SISTEMA:
- Si no sabes la respuesta o el cliente hace preguntas fuera de contexto, responde amablemente que solo puedes ayudar con temas relacionados al restaurante.`;
  }

  private async buildCustomerContext(
    tenantId: string,
    customerPhone?: string,
  ): Promise<string> {
    let customerContext = '';
    let needsProfile = true;
    let needsGps = true; // Rastrear si falta ubicación GPS

    if (customerPhone) {
      const customer = await this.prisma.secure.waCustomer.findUnique({
        where: { tenantId_phone: { tenantId, phone: customerPhone } },
      });
      if (customer) {
        customerContext = `\nContexto del Cliente: Hablas con ${customer.name || 'un cliente'}. `;
        if (customer.address) {
          customerContext += `Su dirección registrada es: ${customer.address}. `;
          needsProfile = false;
        } else {
          customerContext += `NO tienes su dirección registrada. `;
        }

        // Verificar si ya tiene coordenadas GPS
        if (customer.lat && customer.lng) {
          needsGps = false;
        }

        customerContext += `NO le pidas estos datos a menos que pida cambiarlos o sea estrictamente necesario.\n`;
      }
    }

    if (needsProfile && !customerContext) {
      customerContext = `\nContexto del Cliente: Es un cliente nuevo. Antes de generar el carrito con \`createSuggestedCart\`, DEBES preguntarle amablemente su NOMBRE y DIRECCIÓN para el envío (a menos que ya te los haya dado en esta charla).\n`;
    } else if (needsProfile) {
      customerContext += `IMPORTANTE: Aún te falta su dirección. Pídesela amablemente antes de concretar la venta.\n`;
    }

    // Instrucción OPCIONAL de GPS: solo si no tenemos coordenadas.
    // Se inyecta siempre pero la IA solo la usa al entregar el link de pago.
    if (needsGps) {
      customerContext += `\nSUGERENCIA GPS (OPCIONAL, NO BLOQUEA LA VENTA): Cuando entregues el link de pago (después de crear el carrito), añade al final de tu mensaje algo como: "📍 Tip: Si quieres que el repartidor te encuentre más fácil, puedes compartir tu ubicación actual por WhatsApp (toca el 📎 o el + y selecciona 'Ubicación'). ¡Es totalmente opcional!" — NUNCA pidas la ubicación ANTES de confirmar el pedido ni la hagas parecer obligatoria.\n`;
    }

    return customerContext;
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { Cron, CronExpression } from '@nestjs/schedule';
import { PrismaService } from '../../../prisma/prisma.service';

@Injectable()
export class WaCartCronService {
  private readonly logger = new Logger(WaCartCronService.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * Ejecutar todos los días a las 3:00 AM.
   * Elimina los carritos (WaCart) cuya fecha de expiración haya sido hace más de 48 horas.
   * Esto evita que la tabla crezca infinitamente con carritos abandonados temporales.
   */
  @Cron('0 3 * * *')
  async cleanExpiredCarts() {
    this.logger.log(
      '🧹 [CRON] Iniciando limpieza de carritos de WhatsApp antiguos...',
    );

    try {
      // Calculamos la fecha límite (hace 48 horas exactas desde este momento)
      // Como el expiresAt ya se crea con +24h, restar 48h desde AHORA
      // significa que fueron creados hace 72h.
      // Para simplificar, buscaremos los que expiraron hace más de 24 horas a partir de ahora,
      // que sumando las 24h de validez darían exactamente 48h de antigüedad.
      const cutOffDate = new Date();
      cutOffDate.setHours(cutOffDate.getHours() - 24); // Expirados hace al menos 24 horas

      // No podemos usar this.prisma.secure aquí porque es un CRON global sin contexto de tenant
      const result = await (this.prisma.secure as any).waCart.deleteMany({
        where: {
          expiresAt: {
            lt: cutOffDate,
          },
        },
      });

      this.logger.log(
        `✅ [CRON] Limpieza completada. ${result.count} carritos antiguos eliminados.`,
      );
    } catch (error) {
      this.logger.error(
        `❌ [CRON] Fallo durante la limpieza de carritos: ${error.message}`,
      );
    }
  }
}

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import axios from 'axios';
import { PrismaService } from '../../../prisma/prisma.service';

@Injectable()
export class WhatsappOnboardingService {
  private readonly logger = new Logger(WhatsappOnboardingService.name);
  private readonly apiUrl = 'https://graph.facebook.com/v21.0';
  private readonly appId = process.env.META_APP_ID;
  private readonly appSecret = process.env.META_APP_SECRET;

  constructor(private readonly prisma: PrismaService) {}

  async processOnboarding(code: string, tenantId: string) {
    if (!this.appId || !this.appSecret) {
      this.logger.error('META_APP_ID o META_APP_SECRET no están configurados');
      throw new BadRequestException(
        'Configuración de Meta incompleta en el servidor',
      );
    }

    try {
      // Paso 1: Intercambiar code por user_access_token
      this.logger.log(
        `[Tenant: ${tenantId}] Intercambiando código por token de acceso...`,
      );
      const tokenResponse = await axios.get(
        `${this.apiUrl}/oauth/access_token`,
        {
          params: {
            client_id: this.appId,
            client_secret: this.appSecret,
            code: code,
          },
        },
      );

      const userAccessToken = tokenResponse.data.access_token;

      // Paso 2: Intercambiar por token de larga duración (Long-lived token)
      this.logger.log(
        `[Tenant: ${tenantId}] Obteniendo token de larga duración...`,
      );
      const longLivedTokenResponse = await axios.get(
        `${this.apiUrl}/oauth/access_token`,
        {
          params: {
            grant_type: 'fb_exchange_token',
            client_id: this.appId,
            client_secret: this.appSecret,
            fb_exchange_token: userAccessToken,
          },
        },
      );

      const longLivedToken = longLivedTokenResponse.data.access_token;

      // Paso 3: Consultar debug_token para obtener el business_id (WABA) y validar permisos
      this.logger.log(
        `[Tenant: ${tenantId}] Validando token y obteniendo IDs...`,
      );
      const debugTokenResponse = await axios.get(`${this.apiUrl}/debug_token`, {
        params: {
          input_token: longLivedToken,
          access_token: `${this.appId}|${this.appSecret}`, // App Token
        },
      });

      const { data } = debugTokenResponse.data;

      // En Embedded Signup, el waba_id suele venir en los granular_scopes o se puede obtener de business_id
      // Pero usualmente se obtiene de la lista de cuentas vinculadas.
      // Para simplificar, asumiremos que el usuario vinculó una cuenta.

      // Obtener las WABAs vinculadas al negocio del usuario
      const wabaResponse = await axios.get(
        `${this.apiUrl}/me/whatsapp_business_accounts`,
        {
          params: { access_token: longLivedToken },
        },
      );

      const waba = wabaResponse.data.data?.[0];
      if (!waba) {
        throw new BadRequestException(
          'No se encontró ninguna cuenta de WhatsApp Business Account vinculada',
        );
      }

      const wabaId = waba.id;

      // Paso 4: Obtener el ID del número de teléfono
      this.logger.log(
        `[Tenant: ${tenantId}] Obteniendo ID del número de teléfono para WABA: ${wabaId}...`,
      );
      const phoneResponse = await axios.get(
        `${this.apiUrl}/${wabaId}/phone_numbers`,
        {
          params: { access_token: longLivedToken },
        },
      );

      const phoneNumber = phoneResponse.data.data?.[0];
      if (!phoneNumber) {
        throw new BadRequestException(
          'No se encontró ningún número de teléfono vinculado a la WABA',
        );
      }

      const waPhoneNumberId = phoneNumber.id;

      // Persistir en base de datos
      this.logger.log(
        `[Tenant: ${tenantId}] Guardando credenciales de WhatsApp: PhoneID ${waPhoneNumberId}, WabaID ${wabaId}`,
      );

      await (this.prisma.secure as any).storeSettings.upsert({
        where: { tenantId },
        update: {
          waAccessToken: longLivedToken,
          waPhoneNumberId: waPhoneNumberId,
          wabaId: wabaId,
        },
        create: {
          tenantId,
          waAccessToken: longLivedToken,
          waPhoneNumberId: waPhoneNumberId,
          wabaId: wabaId,
        },
      });

      return {
        success: true,
        message: 'Onboarding completado exitosamente',
        data: {
          wabaId,
          waPhoneNumberId,
        },
      };
    } catch (error) {
      const errorMsg = error.response?.data?.error?.message || error.message;
      this.logger.error(
        `[Tenant: ${tenantId}] Error en WhatsApp Onboarding: ${errorMsg}`,
      );
      throw new BadRequestException(
        `Error en la integración con Meta: ${errorMsg}`,
      );
    }
  }
}

import {
  Controller,
  Get,
  Param,
  NotFoundException,
  Logger,
  Headers,
} from '@nestjs/common';
import { Public } from '../../common/decorators/public.decorator';
import { PrismaService } from '../../prisma/prisma.service';

@Public()
@Controller('wa-cart')
export class WaCartController {
  private readonly logger = new Logger(WaCartController.name);

  constructor(private readonly prisma: PrismaService) {}

  /**
   * GET /api/wa-cart/:id
   * Endpoint público que retorna los datos del carrito temporal de WhatsApp desde Postgres.
   */
  @Get(':id')
  async getCart(
    @Param('id') id: string,
    @Headers('x-tenant-id') tenantId?: string,
  ) {
    this.logger.log(
      `[GET_CART] Consultando Postgres id=${id}, tenantId=${tenantId || 'NO_HEADER'}`,
    );

    let cart;

    if (tenantId) {
      // Prioritario: Buscar de forma segura con el tenantId provisto
      cart = await (this.prisma.secure as any).waCart.findUnique({
        where: { id: id, tenantId: tenantId },
      });
      if (cart) {
        this.logger.log(
          `[GET_CART] ✅ Carrito encontrado con tenantId: ${tenantId}`,
        );
      }
    }

    // Fallback: Si no hay tenantId en los headers o no lo encontró, buscar solo por ID
    // Esto previene que una desincronización de headers rompa el carrito
    if (!cart) {
      cart = await (this.prisma.secure as any).waCart.findFirst({
        where: { id: id },
      });
      if (cart) {
        this.logger.log(
          `[GET_CART] ✅ Carrito encontrado vía fallback de ID. Tenant asociado: ${cart.tenantId}`,
        );
      }
    }

    if (!cart) {
      this.logger.warn(
        `[GET_CART] ❌ Carrito NO encontrado en DB. ID=${id}, TenantID=${tenantId || 'N/A'}`,
      );
      throw new NotFoundException('El enlace de pago es inválido o ya expiró.');
    }

    // Comprobar expiración manualmente por seguridad
    if (new Date() > cart.expiresAt) {
      this.logger.warn(`[GET_CART] 🚨 Carrito expirado en DB. ID=${id}`);
      throw new NotFoundException(
        'El enlace de pago ya expiró (duración 24 horas).',
      );
    }

    try {
      const cartData =
        typeof cart.cartData === 'string'
          ? JSON.parse(cart.cartData)
          : cart.cartData;
      this.logger.log(
        `[GET_CART] Carrito servido exitosamente (items=${cartData.items?.length || 0})`,
      );
      return {
        items: cartData.items,
        customerData: cartData.customerData,
        source: 'database',
      };
    } catch (error) {
      this.logger.error(
        `[GET_CART] Error parseando datos del carrito (${id}): ${error.message}`,
      );
      throw new NotFoundException(
        'Error recuperando los datos de este pedido.',
      );
    }
  }
}

import {
